static void *cct_rt_check_not_null(void *p, const char *ctx) {
    if (!p) cct_rt_fail((ctx && *ctx) ? ctx : "null pointer");
    return p;
}

static void *cct_rt_check_not_null_fractum(void *p, const char *ctx) {
    if (!p) {
        cct_rt_fractum_throw_str((ctx && *ctx) ? ctx : "null pointer");
        return (void*)&cct_rt_null_sentinel;
    }
    return p;
}

typedef struct {
    long long is_some;
    size_t value_size;
    unsigned char payload[];
} cct_rt_option_t;

static cct_rt_option_t *cct_rt_option_require(void *opt) {
    if (!opt) cct_rt_fail("option runtime received null option pointer");
    return (cct_rt_option_t*)opt;
}

static void *cct_rt_option_some(const void *value_ptr, size_t value_size) {
    if (!value_ptr) cct_rt_fail("option Some requires non-null value pointer");
    cct_rt_option_t *opt = (cct_rt_option_t*)cct_rt_alloc_or_fail(sizeof(cct_rt_option_t) + value_size);
    opt->is_some = 1;
    opt->value_size = value_size;
    if (value_size > 0) memcpy(opt->payload, value_ptr, value_size);
    return opt;
}

static void *cct_rt_option_none(size_t value_size) {
    cct_rt_option_t *opt = (cct_rt_option_t*)cct_rt_alloc_or_fail(sizeof(cct_rt_option_t) + value_size);
    opt->is_some = 0;
    opt->value_size = value_size;
    if (value_size > 0) memset(opt->payload, 0, value_size);
    return opt;
}

static long long cct_rt_option_is_some(const void *opt_ptr) {
    const cct_rt_option_t *opt = (const cct_rt_option_t*)opt_ptr;
    if (!opt) cct_rt_fail("option runtime received null option pointer");
    return opt->is_some ? 1LL : 0LL;
}

static long long cct_rt_option_is_none(const void *opt_ptr) {
    return cct_rt_option_is_some(opt_ptr) ? 0LL : 1LL;
}

static void *cct_rt_option_unwrap_ptr(void *opt_ptr) {
    cct_rt_option_t *opt = cct_rt_option_require(opt_ptr);
    if (!opt->is_some) cct_rt_fail("option_unwrap on None");
    return (void*)opt->payload;
}

static void *cct_rt_option_expect_ptr(void *opt_ptr, const char *message) {
    cct_rt_option_t *opt = cct_rt_option_require(opt_ptr);
    if (!opt->is_some) cct_rt_fail((message && *message) ? message : "option_expect on None");
    return (void*)opt->payload;
}

static void cct_rt_option_free(void *opt_ptr) {
    if (!opt_ptr) return;
    cct_rt_free_ptr(opt_ptr);
}

typedef struct {
    long long is_ok;
    size_t ok_size;
    size_t err_size;
    unsigned char payload[];
} cct_rt_result_t;

static size_t cct_rt_result_payload_size(size_t ok_size, size_t err_size) {
    return ok_size >= err_size ? ok_size : err_size;
}

static cct_rt_result_t *cct_rt_result_require(void *res) {
    if (!res) cct_rt_fail("result runtime received null result pointer");
    return (cct_rt_result_t*)res;
}

static void *cct_rt_result_ok(const void *value_ptr, size_t ok_size, size_t err_size) {
    if (!value_ptr) cct_rt_fail("result Ok requires non-null payload pointer");
    size_t payload_size = cct_rt_result_payload_size(ok_size, err_size);
    cct_rt_result_t *res = (cct_rt_result_t*)cct_rt_alloc_or_fail(sizeof(cct_rt_result_t) + payload_size);
    res->is_ok = 1;
    res->ok_size = ok_size;
    res->err_size = err_size;
    if (payload_size > 0) memset(res->payload, 0, payload_size);
    if (ok_size > 0) memcpy(res->payload, value_ptr, ok_size);
    return res;
}

static void *cct_rt_result_err(const void *err_ptr, size_t ok_size, size_t err_size) {
    if (!err_ptr) cct_rt_fail("result Err requires non-null payload pointer");
    size_t payload_size = cct_rt_result_payload_size(ok_size, err_size);
    cct_rt_result_t *res = (cct_rt_result_t*)cct_rt_alloc_or_fail(sizeof(cct_rt_result_t) + payload_size);
    res->is_ok = 0;
    res->ok_size = ok_size;
    res->err_size = err_size;
    if (payload_size > 0) memset(res->payload, 0, payload_size);
    if (err_size > 0) memcpy(res->payload, err_ptr, err_size);
    return res;
}

static long long cct_rt_result_is_ok(const void *res_ptr) {
    const cct_rt_result_t *res = (const cct_rt_result_t*)res_ptr;
    if (!res) cct_rt_fail("result runtime received null result pointer");
    return res->is_ok ? 1LL : 0LL;
}

static long long cct_rt_result_is_err(const void *res_ptr) {
    return cct_rt_result_is_ok(res_ptr) ? 0LL : 1LL;
}

static void *cct_rt_result_unwrap_ptr(void *res_ptr) {
    cct_rt_result_t *res = cct_rt_result_require(res_ptr);
    if (!res->is_ok) cct_rt_fail("result_unwrap on Err");
    return (void*)res->payload;
}

static void *cct_rt_result_unwrap_handle(void *res_ptr) {
    cct_rt_result_t *res = cct_rt_result_require(res_ptr);
    if (!res->is_ok) cct_rt_fail("result_unwrap_handle on Err");
    return *(void**)res->payload;
}

static void *cct_rt_result_unwrap_err_ptr(void *res_ptr) {
    cct_rt_result_t *res = cct_rt_result_require(res_ptr);
    if (res->is_ok) cct_rt_fail("result_unwrap_err on Ok");
    return (void*)res->payload;
}

static void *cct_rt_result_expect_ptr(void *res_ptr, const char *message) {
    cct_rt_result_t *res = cct_rt_result_require(res_ptr);
    if (!res->is_ok) cct_rt_fail((message && *message) ? message : "result_expect on Err");
    return (void*)res->payload;
}

static void cct_rt_result_free(void *res_ptr) {
    if (!res_ptr) return;
    cct_rt_free_ptr(res_ptr);
}

typedef long long (*cct_rt_collection_map_fn_t)(long long);
typedef long long (*cct_rt_collection_pred_fn_t)(long long);
typedef long long (*cct_rt_collection_fold_fn_t)(long long, long long);

static long long cct_rt_collection_require_word_size(long long size, const char *ctx) {
    if (size != (long long)sizeof(long long)) {
        cct_rt_fail((ctx && *ctx) ? ctx : "collection operations in subset 12D.2 require word-sized types");
    }
    return size;
}

static long long cct_rt_collection_read_word(const void *ptr, long long size, const char *ctx) {
    if (!ptr) cct_rt_fail((ctx && *ctx) ? ctx : "collection read received null pointer");
    cct_rt_collection_require_word_size(size, ctx);
    long long v = 0;
    memcpy(&v, ptr, sizeof(long long));
    return v;
}

static void cct_rt_collection_write_word(void *ptr, long long size, long long value, const char *ctx) {
    if (!ptr) cct_rt_fail((ctx && *ctx) ? ctx : "collection write received null pointer");
    cct_rt_collection_require_word_size(size, ctx);
    memcpy(ptr, &value, sizeof(long long));
}

static void *cct_rt_collection_fluxus_map(void *flux_ptr, long long item_size, long long result_size, void *fn_ptr) {
    cct_rt_fluxus_require(flux_ptr, "collection_fluxus_map received null fluxus");
    if (!fn_ptr) cct_rt_fail("collection_fluxus_map received null callback");
    cct_rt_collection_require_word_size(item_size, "collection_fluxus_map only supports word-sized input in subset 12D.2");
    cct_rt_collection_require_word_size(result_size, "collection_fluxus_map only supports word-sized output in subset 12D.2");
    cct_rt_collection_map_fn_t fn = (cct_rt_collection_map_fn_t)fn_ptr;
    void *result_flux = cct_rt_fluxus_create(result_size);
    long long len = cct_rt_fluxus_len(flux_ptr);
    for (long long i = 0; i < len; i++) {
        void *item_ptr = cct_rt_fluxus_get(flux_ptr, i);
        long long item = cct_rt_collection_read_word(item_ptr, item_size, "collection_fluxus_map input read failed");
        long long mapped = fn(item);
        cct_rt_fluxus_push(result_flux, &mapped);
    }
    return result_flux;
}

static void *cct_rt_collection_fluxus_filter(void *flux_ptr, long long item_size, void *predicate_ptr) {
    cct_rt_fluxus_require(flux_ptr, "collection_fluxus_filter received null fluxus");
    if (!predicate_ptr) cct_rt_fail("collection_fluxus_filter received null callback");
    cct_rt_collection_require_word_size(item_size, "collection_fluxus_filter only supports word-sized elements in subset 12D.2");
    cct_rt_collection_pred_fn_t pred = (cct_rt_collection_pred_fn_t)predicate_ptr;
    void *result_flux = cct_rt_fluxus_create(item_size);
    long long len = cct_rt_fluxus_len(flux_ptr);
    for (long long i = 0; i < len; i++) {
        void *item_ptr = cct_rt_fluxus_get(flux_ptr, i);
        long long item = cct_rt_collection_read_word(item_ptr, item_size, "collection_fluxus_filter input read failed");
        if (pred(item)) cct_rt_fluxus_push(result_flux, &item);
    }
    return result_flux;
}

static void *cct_rt_collection_fluxus_fold(void *flux_ptr, long long item_size, const void *initial_ptr, long long acc_size, void *fn_ptr) {
    cct_rt_fluxus_require(flux_ptr, "collection_fluxus_fold received null fluxus");
    if (!initial_ptr) cct_rt_fail("collection_fluxus_fold received null initial accumulator pointer");
    if (!fn_ptr) cct_rt_fail("collection_fluxus_fold received null callback");
    cct_rt_collection_require_word_size(item_size, "collection_fluxus_fold only supports word-sized element type in subset 12D.2");
    cct_rt_collection_require_word_size(acc_size, "collection_fluxus_fold only supports word-sized accumulator type in subset 12D.2");
    cct_rt_collection_fold_fn_t fn = (cct_rt_collection_fold_fn_t)fn_ptr;
    long long acc = cct_rt_collection_read_word(initial_ptr, acc_size, "collection_fluxus_fold failed to read initial accumulator");
    long long len = cct_rt_fluxus_len(flux_ptr);
    for (long long i = 0; i < len; i++) {
        void *item_ptr = cct_rt_fluxus_get(flux_ptr, i);
        long long item = cct_rt_collection_read_word(item_ptr, item_size, "collection_fluxus_fold input read failed");
        acc = fn(acc, item);
    }
    void *acc_ptr = cct_rt_alloc_or_fail((size_t)acc_size);
    cct_rt_collection_write_word(acc_ptr, acc_size, acc, "collection_fluxus_fold failed to materialize accumulator");
    return acc_ptr;
}

