typedef struct cct_rt_map_entry {
    unsigned char *key;
    unsigned char *value;
    struct cct_rt_map_entry *next;
} cct_rt_map_entry_t;

typedef struct {
    cct_rt_map_entry_t **buckets;
    size_t capacity;
    size_t len;
    size_t key_size;
    size_t value_size;
    cct_rt_map_entry_t **insert_order;
    size_t insert_capacity;
} cct_rt_map_t;

typedef struct {
    cct_rt_map_t *map;
} cct_rt_set_t;

static size_t cct_rt_map_min_storage_size(size_t n) {
    return (n == 0) ? 1 : n;
}

static size_t cct_rt_map_hash_bytes(const void *data, size_t size) {
    const unsigned char *p = (const unsigned char*)data;
    size_t h = (size_t)1469598103934665603ULL;
    for (size_t i = 0; i < size; i++) {
        h ^= (size_t)p[i];
        h *= (size_t)1099511628211ULL;
    }
    return h;
}

static void cct_rt_map_require(void *map_ptr, const char *ctx) {
    if (!map_ptr) cct_rt_fail((ctx && *ctx) ? ctx : "map received null instance");
}

static cct_rt_map_entry_t *cct_rt_map_entry_new(const void *key_ptr, size_t key_size, const void *value_ptr, size_t value_size) {
    cct_rt_map_entry_t *e = (cct_rt_map_entry_t*)cct_rt_alloc_or_fail(sizeof(cct_rt_map_entry_t));
    e->key = (unsigned char*)cct_rt_alloc_or_fail(key_size);
    e->value = (unsigned char*)cct_rt_alloc_or_fail(value_size);
    memcpy(e->key, key_ptr, key_size);
    memcpy(e->value, value_ptr, value_size);
    e->next = NULL;
    return e;
}

static void cct_rt_map_entry_free(cct_rt_map_entry_t *e) {
    if (!e) return;
    cct_rt_free_ptr(e->key);
    cct_rt_free_ptr(e->value);
    cct_rt_free_ptr(e);
}

static void cct_rt_map_insert_order_reserve(cct_rt_map_t *map, size_t needed) {
    if (needed <= map->insert_capacity) return;
    size_t cap = map->insert_capacity ? map->insert_capacity * 2 : 16;
    while (cap < needed) cap *= 2;
    cct_rt_map_entry_t **next = (cct_rt_map_entry_t**)realloc(map->insert_order, cap * sizeof(cct_rt_map_entry_t*));
    if (!next) cct_rt_fail("map insert-order allocation failed");
    map->insert_order = next;
    map->insert_capacity = cap;
}

static void cct_rt_map_insert_order_append(cct_rt_map_t *map, cct_rt_map_entry_t *entry) {
    cct_rt_map_insert_order_reserve(map, map->len + 1);
    map->insert_order[map->len] = entry;
}

static void cct_rt_map_insert_order_remove(cct_rt_map_t *map, cct_rt_map_entry_t *entry) {
    if (!map || !entry || map->len == 0) return;
    for (size_t i = 0; i < map->len; i++) {
        if (map->insert_order[i] != entry) continue;
        if (i + 1 < map->len) {
            memmove(&map->insert_order[i], &map->insert_order[i + 1], (map->len - i - 1) * sizeof(cct_rt_map_entry_t*));
        }
        map->insert_order[map->len - 1] = NULL;
        return;
    }
}

static size_t cct_rt_map_bucket_index(cct_rt_map_t *map, const void *key_ptr) {
    size_t h = cct_rt_map_hash_bytes(key_ptr, map->key_size);
    return (map->capacity == 0) ? 0 : (h % map->capacity);
}

static void cct_rt_map_rehash(cct_rt_map_t *map, size_t new_capacity) {
    cct_rt_map_entry_t **new_buckets = (cct_rt_map_entry_t**)calloc(new_capacity, sizeof(cct_rt_map_entry_t*));
    if (!new_buckets) cct_rt_fail("map rehash allocation failed");
    for (size_t i = 0; i < map->capacity; i++) {
        cct_rt_map_entry_t *e = map->buckets[i];
        while (e) {
            cct_rt_map_entry_t *next = e->next;
            size_t idx = cct_rt_map_hash_bytes(e->key, map->key_size) % new_capacity;
            e->next = new_buckets[idx];
            new_buckets[idx] = e;
            e = next;
        }
    }
    cct_rt_free_ptr(map->buckets);
    map->buckets = new_buckets;
    map->capacity = new_capacity;
}

static void *cct_rt_map_init(long long key_size, long long value_size) {
    if (key_size <= 0) cct_rt_fail("map_init key size must be > 0");
    if (value_size < 0) cct_rt_fail("map_init value size must be >= 0");
    cct_rt_map_t *map = (cct_rt_map_t*)cct_rt_alloc_or_fail(sizeof(cct_rt_map_t));
    map->capacity = 16;
    map->len = 0;
    map->key_size = cct_rt_map_min_storage_size((size_t)key_size);
    map->value_size = cct_rt_map_min_storage_size((size_t)value_size);
    map->buckets = (cct_rt_map_entry_t**)calloc(map->capacity, sizeof(cct_rt_map_entry_t*));
    if (!map->buckets) cct_rt_fail("map_init buckets allocation failed");
    map->insert_order = NULL;
    map->insert_capacity = 0;
    return map;
}

static void cct_rt_map_insert(void *map_ptr, const void *key_ptr, const void *value_ptr) {
    cct_rt_map_require(map_ptr, "map_insert received null map");
    if (!key_ptr) cct_rt_fail("map_insert received null key pointer");
    if (!value_ptr) cct_rt_fail("map_insert received null value pointer");
    cct_rt_map_t *map = (cct_rt_map_t*)map_ptr;
    if (map->capacity == 0) cct_rt_fail("map_insert map capacity invalid");
    if ((map->len + 1) * 4 >= map->capacity * 3) {
        cct_rt_map_rehash(map, map->capacity * 2);
    }
    size_t idx = cct_rt_map_bucket_index(map, key_ptr);
    cct_rt_map_entry_t *e = map->buckets[idx];
    while (e) {
        if (memcmp(e->key, key_ptr, map->key_size) == 0) {
            memcpy(e->value, value_ptr, map->value_size);
            return;
        }
        e = e->next;
    }
    cct_rt_map_entry_t *ne = cct_rt_map_entry_new(key_ptr, map->key_size, value_ptr, map->value_size);
    ne->next = map->buckets[idx];
    map->buckets[idx] = ne;
    cct_rt_map_insert_order_append(map, ne);
    map->len += 1;
}

static void *cct_rt_map_get_ptr(void *map_ptr, const void *key_ptr) {
    cct_rt_map_require(map_ptr, "map_get_ptr received null map");
    if (!key_ptr) cct_rt_fail("map_get_ptr received null key pointer");
    cct_rt_map_t *map = (cct_rt_map_t*)map_ptr;
    size_t idx = cct_rt_map_bucket_index(map, key_ptr);
    cct_rt_map_entry_t *e = map->buckets[idx];
    while (e) {
        if (memcmp(e->key, key_ptr, map->key_size) == 0) return (void*)e->value;
        e = e->next;
    }
    return NULL;
}

static long long cct_rt_map_contains(void *map_ptr, const void *key_ptr) {
    return cct_rt_map_get_ptr(map_ptr, key_ptr) ? 1LL : 0LL;
}

static long long cct_rt_map_remove(void *map_ptr, const void *key_ptr) {
    cct_rt_map_require(map_ptr, "map_remove received null map");
    if (!key_ptr) cct_rt_fail("map_remove received null key pointer");
    cct_rt_map_t *map = (cct_rt_map_t*)map_ptr;
    size_t idx = cct_rt_map_bucket_index(map, key_ptr);
    cct_rt_map_entry_t *e = map->buckets[idx];
    cct_rt_map_entry_t *prev = NULL;
    while (e) {
        if (memcmp(e->key, key_ptr, map->key_size) == 0) {
            if (prev) prev->next = e->next;
            else map->buckets[idx] = e->next;
            cct_rt_map_insert_order_remove(map, e);
            cct_rt_map_entry_free(e);
            map->len -= 1;
            return 1LL;
        }
        prev = e;
        e = e->next;
    }
    return 0LL;
}

static long long cct_rt_map_len(void *map_ptr) {
    cct_rt_map_require(map_ptr, "map_len received null map");
    return (long long)((cct_rt_map_t*)map_ptr)->len;
}

static long long cct_rt_map_is_empty(void *map_ptr) {
    return cct_rt_map_len(map_ptr) == 0 ? 1LL : 0LL;
}

static long long cct_rt_map_capacity(void *map_ptr) {
    cct_rt_map_require(map_ptr, "map_capacity received null map");
    return (long long)((cct_rt_map_t*)map_ptr)->capacity;
}

static void cct_rt_map_clear(void *map_ptr) {
    cct_rt_map_require(map_ptr, "map_clear received null map");
    cct_rt_map_t *map = (cct_rt_map_t*)map_ptr;
    for (size_t i = 0; i < map->capacity; i++) {
        cct_rt_map_entry_t *e = map->buckets[i];
        while (e) {
            cct_rt_map_entry_t *next = e->next;
            cct_rt_map_entry_free(e);
            e = next;
        }
        map->buckets[i] = NULL;
    }
    if (map->insert_order && map->len > 0) {
        memset(map->insert_order, 0, map->len * sizeof(cct_rt_map_entry_t*));
    }
    map->len = 0;
}

static void cct_rt_map_reserve(void *map_ptr, long long additional) {
    cct_rt_map_require(map_ptr, "map_reserve received null map");
    if (additional < 0) cct_rt_fail("map_reserve additional must be >= 0");
    cct_rt_map_t *map = (cct_rt_map_t*)map_ptr;
    size_t need = map->len + (size_t)additional;
    size_t target = map->capacity;
    while (need * 4 >= target * 3) {
        target *= 2;
    }
    if (target > map->capacity) cct_rt_map_rehash(map, target);
}

static void *cct_rt_map_copy(void *map_ptr) {
    cct_rt_map_require(map_ptr, "map_copy received null map");
    cct_rt_map_t *src = (cct_rt_map_t*)map_ptr;
    cct_rt_map_t *dst = (cct_rt_map_t*)cct_rt_map_init((long long)src->key_size, (long long)src->value_size);
    cct_rt_map_reserve(dst, (long long)src->len);
    for (size_t i = 0; i < src->len; i++) {
        cct_rt_map_entry_t *e = src->insert_order[i];
        if (!e) continue;
        cct_rt_map_insert(dst, (const void*)e->key, (const void*)e->value);
    }
    return dst;
}

static void *cct_rt_map_keys(void *map_ptr, long long key_size) {
    cct_rt_map_require(map_ptr, "map_keys received null map");
    if (key_size <= 0) cct_rt_fail("map_keys key_size must be > 0");
    cct_rt_map_t *map = (cct_rt_map_t*)map_ptr;
    if (cct_rt_map_min_storage_size((size_t)key_size) != map->key_size) cct_rt_fail("map_keys key_size mismatch");
    void *out_f = cct_rt_fluxus_create(key_size);
    cct_rt_fluxus_reserve(out_f, (long long)map->len);
    for (size_t i = 0; i < map->len; i++) {
        cct_rt_map_entry_t *e = map->insert_order[i];
        if (!e) continue;
        cct_rt_fluxus_push(out_f, (const void*)e->key);
    }
    return out_f;
}

static void *cct_rt_map_values(void *map_ptr, long long value_size) {
    cct_rt_map_require(map_ptr, "map_values received null map");
    if (value_size <= 0) cct_rt_fail("map_values value_size must be > 0");
    cct_rt_map_t *map = (cct_rt_map_t*)map_ptr;
    if (cct_rt_map_min_storage_size((size_t)value_size) != map->value_size) cct_rt_fail("map_values value_size mismatch");
    void *out_f = cct_rt_fluxus_create(value_size);
    cct_rt_fluxus_reserve(out_f, (long long)map->len);
    for (size_t i = 0; i < map->len; i++) {
        cct_rt_map_entry_t *e = map->insert_order[i];
        if (!e) continue;
        cct_rt_fluxus_push(out_f, (const void*)e->value);
    }
    return out_f;
}

static void cct_rt_map_merge(void *dest_ptr, void *src_ptr) {
    cct_rt_map_require(dest_ptr, "map_merge received null destination map");
    cct_rt_map_require(src_ptr, "map_merge received null source map");
    cct_rt_map_t *dest = (cct_rt_map_t*)dest_ptr;
    cct_rt_map_t *src = (cct_rt_map_t*)src_ptr;
    if (dest->key_size != src->key_size || dest->value_size != src->value_size) cct_rt_fail("map_merge requires compatible key/value sizes");
    cct_rt_map_reserve(dest, (long long)src->len);
    for (size_t i = 0; i < src->len; i++) {
        cct_rt_map_entry_t *e = src->insert_order[i];
        if (!e) continue;
        cct_rt_map_insert(dest, (const void*)e->key, (const void*)e->value);
    }
}

typedef struct {
    cct_rt_map_t *map;
    size_t index;
} cct_rt_map_iter_t;

static void *cct_rt_map_iter_begin(void *map_ptr) {
    cct_rt_map_require(map_ptr, "map_iter_begin received null map");
    cct_rt_map_iter_t *it = (cct_rt_map_iter_t*)cct_rt_alloc_or_fail(sizeof(cct_rt_map_iter_t));
    it->map = (cct_rt_map_t*)map_ptr;
    it->index = 0;
    return it;
}

static long long cct_rt_map_iter_next(void *iter_ptr, void **key_ptr_out, void **value_ptr_out) {
    if (!iter_ptr) cct_rt_fail("map_iter_next received null iterator");
    if (!key_ptr_out || !value_ptr_out) cct_rt_fail("map_iter_next requires key/value out pointers");
    cct_rt_map_iter_t *it = (cct_rt_map_iter_t*)iter_ptr;
    if (!it->map) cct_rt_fail("map_iter_next iterator has null map");
    while (it->index < it->map->len) {
        cct_rt_map_entry_t *e = it->map->insert_order[it->index++];
        if (!e) continue;
        *key_ptr_out = (void*)e->key;
        *value_ptr_out = (void*)e->value;
        return 1LL;
    }
    return 0LL;
}

static void cct_rt_map_iter_end(void *iter_ptr) {
    if (!iter_ptr) return;
    cct_rt_free_ptr(iter_ptr);
}

static void cct_rt_map_free(void *map_ptr) {
    if (!map_ptr) return;
    cct_rt_map_t *map = (cct_rt_map_t*)map_ptr;
    cct_rt_map_clear(map);
    cct_rt_free_ptr(map->buckets);
    cct_rt_free_ptr(map->insert_order);
    cct_rt_free_ptr(map);
}

static void *cct_rt_set_init(long long item_size) {
    cct_rt_set_t *set = (cct_rt_set_t*)cct_rt_alloc_or_fail(sizeof(cct_rt_set_t));
    set->map = (cct_rt_map_t*)cct_rt_map_init(item_size, 1);
    return set;
}

static long long cct_rt_set_insert(void *set_ptr, const void *item_ptr) {
    if (!set_ptr) cct_rt_fail("set_insert received null set");
    if (!item_ptr) cct_rt_fail("set_insert received null item pointer");
    cct_rt_set_t *set = (cct_rt_set_t*)set_ptr;
    size_t before = set->map->len;
    unsigned char marker = 1;
    cct_rt_map_insert(set->map, item_ptr, &marker);
    return (set->map->len > before) ? 1LL : 0LL;
}

static long long cct_rt_set_remove(void *set_ptr, const void *item_ptr) {
    if (!set_ptr) cct_rt_fail("set_remove received null set");
    if (!item_ptr) cct_rt_fail("set_remove received null item pointer");
    return cct_rt_map_remove(((cct_rt_set_t*)set_ptr)->map, item_ptr);
}

static long long cct_rt_set_contains(void *set_ptr, const void *item_ptr) {
    if (!set_ptr) cct_rt_fail("set_contains received null set");
    if (!item_ptr) cct_rt_fail("set_contains received null item pointer");
    return cct_rt_map_contains(((cct_rt_set_t*)set_ptr)->map, item_ptr);
}

static long long cct_rt_set_len(void *set_ptr) {
    if (!set_ptr) cct_rt_fail("set_len received null set");
    return cct_rt_map_len(((cct_rt_set_t*)set_ptr)->map);
}

static long long cct_rt_set_is_empty(void *set_ptr) {
    return cct_rt_set_len(set_ptr) == 0 ? 1LL : 0LL;
}

static void cct_rt_set_clear(void *set_ptr) {
    if (!set_ptr) cct_rt_fail("set_clear received null set");
    cct_rt_map_clear(((cct_rt_set_t*)set_ptr)->map);
}

static void cct_rt_set_reserve(void *set_ptr, long long additional) {
    if (!set_ptr) cct_rt_fail("set_reserve received null set");
    cct_rt_map_reserve(((cct_rt_set_t*)set_ptr)->map, additional);
}

static long long cct_rt_set_capacity(void *set_ptr) {
    if (!set_ptr) cct_rt_fail("set_capacity received null set");
    return cct_rt_map_capacity(((cct_rt_set_t*)set_ptr)->map);
}

typedef struct {
    cct_rt_set_t *set;
    size_t index;
} cct_rt_set_iter_t;

static void *cct_rt_set_iter_begin(void *set_ptr) {
    if (!set_ptr) cct_rt_fail("set_iter_begin received null set");
    cct_rt_set_iter_t *it = (cct_rt_set_iter_t*)cct_rt_alloc_or_fail(sizeof(cct_rt_set_iter_t));
    it->set = (cct_rt_set_t*)set_ptr;
    it->index = 0;
    return it;
}

static long long cct_rt_set_iter_next(void *iter_ptr, void **elem_ptr_out) {
    if (!iter_ptr) cct_rt_fail("set_iter_next received null iterator");
    if (!elem_ptr_out) cct_rt_fail("set_iter_next requires elem out pointer");
    cct_rt_set_iter_t *it = (cct_rt_set_iter_t*)iter_ptr;
    if (!it->set || !it->set->map) cct_rt_fail("set_iter_next iterator has null set/map");
    while (it->index < it->set->map->len) {
        cct_rt_map_entry_t *e = it->set->map->insert_order[it->index++];
        if (!e) continue;
        *elem_ptr_out = (void*)e->key;
        return 1LL;
    }
    return 0LL;
}

static void cct_rt_set_iter_end(void *iter_ptr) {
    if (!iter_ptr) return;
    cct_rt_free_ptr(iter_ptr);
}

static long long cct_rt_set_validate_item_size(cct_rt_set_t *set, long long item_size, const char *ctx) {
    if (!set) cct_rt_fail((ctx && *ctx) ? ctx : "set validation received null set");
    if (item_size <= 0) cct_rt_fail("set operation requires item_size > 0");
    if (cct_rt_map_min_storage_size((size_t)item_size) != set->map->key_size) {
        cct_rt_fail("set operation item_size mismatch");
    }
    return item_size;
}

static void *cct_rt_set_copy(void *set_ptr, long long item_size) {
    if (!set_ptr) cct_rt_fail("set_copy received null set");
    cct_rt_set_t *src = (cct_rt_set_t*)set_ptr;
    cct_rt_set_validate_item_size(src, item_size, "set_copy invalid input");
    cct_rt_set_t *dst = (cct_rt_set_t*)cct_rt_set_init(item_size);
    cct_rt_set_reserve(dst, (long long)src->map->len);
    for (size_t i = 0; i < src->map->len; i++) {
        cct_rt_map_entry_t *e = src->map->insert_order[i];
        if (!e) continue;
        cct_rt_set_insert(dst, (const void*)e->key);
    }
    return dst;
}

static void *cct_rt_set_to_fluxus(void *set_ptr, long long item_size) {
    if (!set_ptr) cct_rt_fail("set_to_fluxus received null set");
    cct_rt_set_t *set = (cct_rt_set_t*)set_ptr;
    cct_rt_set_validate_item_size(set, item_size, "set_to_fluxus invalid input");
    void *out_f = cct_rt_fluxus_create(item_size);
    cct_rt_fluxus_reserve(out_f, (long long)set->map->len);
    for (size_t i = 0; i < set->map->len; i++) {
        cct_rt_map_entry_t *e = set->map->insert_order[i];
        if (!e) continue;
        cct_rt_fluxus_push(out_f, (const void*)e->key);
    }
    return out_f;
}

static long long cct_rt_set_is_subset(void *a_ptr, void *b_ptr, long long item_size) {
    if (!a_ptr || !b_ptr) cct_rt_fail("set_is_subset received null set");
    cct_rt_set_t *a = (cct_rt_set_t*)a_ptr;
    cct_rt_set_t *b = (cct_rt_set_t*)b_ptr;
    cct_rt_set_validate_item_size(a, item_size, "set_is_subset invalid left set");
    cct_rt_set_validate_item_size(b, item_size, "set_is_subset invalid right set");
    if (a->map->len > b->map->len) return 0LL;
    for (size_t i = 0; i < a->map->len; i++) {
        cct_rt_map_entry_t *e = a->map->insert_order[i];
        if (!e) continue;
        if (!cct_rt_set_contains(b, (const void*)e->key)) return 0LL;
    }
    return 1LL;
}

static long long cct_rt_set_equals(void *a_ptr, void *b_ptr, long long item_size) {
    if (!a_ptr || !b_ptr) cct_rt_fail("set_equals received null set");
    cct_rt_set_t *a = (cct_rt_set_t*)a_ptr;
    cct_rt_set_t *b = (cct_rt_set_t*)b_ptr;
    cct_rt_set_validate_item_size(a, item_size, "set_equals invalid left set");
    cct_rt_set_validate_item_size(b, item_size, "set_equals invalid right set");
    if (a->map->len != b->map->len) return 0LL;
    return cct_rt_set_is_subset(a, b, item_size);
}

static void *cct_rt_set_union(void *a_ptr, void *b_ptr, long long item_size) {
    if (!a_ptr || !b_ptr) cct_rt_fail("set_union received null set");
    cct_rt_set_t *a = (cct_rt_set_t*)a_ptr;
    cct_rt_set_t *b = (cct_rt_set_t*)b_ptr;
    cct_rt_set_validate_item_size(a, item_size, "set_union invalid left set");
    cct_rt_set_validate_item_size(b, item_size, "set_union invalid right set");
    cct_rt_set_t *out_s = (cct_rt_set_t*)cct_rt_set_copy(a, item_size);
    cct_rt_set_reserve(out_s, (long long)b->map->len);
    for (size_t i = 0; i < b->map->len; i++) {
        cct_rt_map_entry_t *e = b->map->insert_order[i];
        if (!e) continue;
        cct_rt_set_insert(out_s, (const void*)e->key);
    }
    return out_s;
}

static void *cct_rt_set_intersection(void *a_ptr, void *b_ptr, long long item_size) {
    if (!a_ptr || !b_ptr) cct_rt_fail("set_intersection received null set");
    cct_rt_set_t *a = (cct_rt_set_t*)a_ptr;
    cct_rt_set_t *b = (cct_rt_set_t*)b_ptr;
    cct_rt_set_validate_item_size(a, item_size, "set_intersection invalid left set");
    cct_rt_set_validate_item_size(b, item_size, "set_intersection invalid right set");
    cct_rt_set_t *out_s = (cct_rt_set_t*)cct_rt_set_init(item_size);
    cct_rt_set_t *probe = (a->map->len <= b->map->len) ? a : b;
    cct_rt_set_t *other = (probe == a) ? b : a;
    cct_rt_set_reserve(out_s, (long long)probe->map->len);
    for (size_t i = 0; i < probe->map->len; i++) {
        cct_rt_map_entry_t *e = probe->map->insert_order[i];
        if (!e) continue;
        if (cct_rt_set_contains(other, (const void*)e->key)) cct_rt_set_insert(out_s, (const void*)e->key);
    }
    return out_s;
}

static void *cct_rt_set_difference(void *a_ptr, void *b_ptr, long long item_size) {
    if (!a_ptr || !b_ptr) cct_rt_fail("set_difference received null set");
    cct_rt_set_t *a = (cct_rt_set_t*)a_ptr;
    cct_rt_set_t *b = (cct_rt_set_t*)b_ptr;
    cct_rt_set_validate_item_size(a, item_size, "set_difference invalid left set");
    cct_rt_set_validate_item_size(b, item_size, "set_difference invalid right set");
    cct_rt_set_t *out_s = (cct_rt_set_t*)cct_rt_set_init(item_size);
    cct_rt_set_reserve(out_s, (long long)a->map->len);
    for (size_t i = 0; i < a->map->len; i++) {
        cct_rt_map_entry_t *e = a->map->insert_order[i];
        if (!e) continue;
        if (!cct_rt_set_contains(b, (const void*)e->key)) cct_rt_set_insert(out_s, (const void*)e->key);
    }
    return out_s;
}

static void *cct_rt_set_symmetric_difference(void *a_ptr, void *b_ptr, long long item_size) {
    if (!a_ptr || !b_ptr) cct_rt_fail("set_symmetric_difference received null set");
    cct_rt_set_t *a = (cct_rt_set_t*)a_ptr;
    cct_rt_set_t *b = (cct_rt_set_t*)b_ptr;
    cct_rt_set_validate_item_size(a, item_size, "set_symmetric_difference invalid left set");
    cct_rt_set_validate_item_size(b, item_size, "set_symmetric_difference invalid right set");
    cct_rt_set_t *out_s = (cct_rt_set_t*)cct_rt_set_init(item_size);
    cct_rt_set_reserve(out_s, (long long)(a->map->len + b->map->len));
    for (size_t i = 0; i < a->map->len; i++) {
        cct_rt_map_entry_t *e = a->map->insert_order[i];
        if (!e) continue;
        if (!cct_rt_set_contains(b, (const void*)e->key)) cct_rt_set_insert(out_s, (const void*)e->key);
    }
    for (size_t i = 0; i < b->map->len; i++) {
        cct_rt_map_entry_t *e = b->map->insert_order[i];
        if (!e) continue;
        if (!cct_rt_set_contains(a, (const void*)e->key)) cct_rt_set_insert(out_s, (const void*)e->key);
    }
    return out_s;
}

static void cct_rt_set_free(void *set_ptr) {
    if (!set_ptr) return;
    cct_rt_set_t *set = (cct_rt_set_t*)set_ptr;
    cct_rt_map_free(set->map);
    cct_rt_free_ptr(set);
}

typedef struct {
    char *buf;
    size_t len;
    size_t cap;
} cct_rt_molde_ctx_t;

static cct_rt_molde_ctx_t *cct_rt_molde_begin(void) {
    cct_rt_molde_ctx_t *m = (cct_rt_molde_ctx_t*)malloc(sizeof(cct_rt_molde_ctx_t));
    if (!m) cct_rt_fail("MOLDE allocation failed");
    m->cap = 128;
    m->len = 0;
    m->buf = (char*)malloc(m->cap);
    if (!m->buf) cct_rt_fail("MOLDE buffer allocation failed");
    m->buf[0] = '\0';
    return m;
}

static void cct_rt_molde_append(cct_rt_molde_ctx_t *m, const char *s, size_t slen) {
    if (!m || !s || slen == 0) return;
    while (m->len + slen + 1 > m->cap) {
        size_t next = m->cap * 2;
        if (next <= m->cap) cct_rt_fail("MOLDE buffer overflow");
        char *grown = (char*)realloc(m->buf, next);
        if (!grown) cct_rt_fail("MOLDE realloc failed");
        m->buf = grown;
        m->cap = next;
    }
    memcpy(m->buf + m->len, s, slen);
    m->len += slen;
    m->buf[m->len] = '\0';
}

static void cct_rt_molde_str(cct_rt_molde_ctx_t *m, const char *s) {
    const char *src = s ? s : "";
    cct_rt_molde_append(m, src, strlen(src));
}

static void cct_rt_molde_rex(cct_rt_molde_ctx_t *m, long long v) {
    char tmp[64];
    int n = snprintf(tmp, sizeof(tmp), "%lld", v);
    if (n < 0) cct_rt_fail("MOLDE rex formatting failed");
    cct_rt_molde_append(m, tmp, (size_t)n);
}

static void cct_rt_molde_dux(cct_rt_molde_ctx_t *m, unsigned long long v) {
    char tmp[64];
    int n = snprintf(tmp, sizeof(tmp), "%llu", v);
    if (n < 0) cct_rt_fail("MOLDE dux formatting failed");
    cct_rt_molde_append(m, tmp, (size_t)n);
}

static void cct_rt_molde_umbra(cct_rt_molde_ctx_t *m, double v) {
    char tmp[128];
    int n = snprintf(tmp, sizeof(tmp), "%g", v);
    if (n < 0) cct_rt_fail("MOLDE umbra formatting failed");
    cct_rt_molde_append(m, tmp, (size_t)n);
}

static void cct_rt_molde_verum(cct_rt_molde_ctx_t *m, long long v) {
    const char *txt = v ? "verum" : "falsum";
    cct_rt_molde_append(m, txt, strlen(txt));
}

static void cct_rt_molde_fmt_build(char *fmt, size_t fmt_cap, const char *spec, const char *length_mod) {
    if (!fmt || fmt_cap == 0) cct_rt_fail("MOLDE format buffer invalid");
    if (!spec || !spec[0]) cct_rt_fail("MOLDE format spec vazio");
    size_t spec_len = strlen(spec);
    char conv = spec[spec_len - 1];
    size_t prefix_len = spec_len - 1;
    int n;
    if (length_mod && length_mod[0]) n = snprintf(fmt, fmt_cap, "%%%.*s%s%c", (int)prefix_len, spec, length_mod, conv);
    else n = snprintf(fmt, fmt_cap, "%%%s", spec);
    if (n < 0 || (size_t)n >= fmt_cap) cct_rt_fail("MOLDE format spec overflow");
}

static void cct_rt_molde_rex_fmt(cct_rt_molde_ctx_t *m, long long v, const char *spec) {
    char fmt[64];
    cct_rt_molde_fmt_build(fmt, sizeof(fmt), spec, "ll");
    int need = snprintf(NULL, 0, fmt, v);
    if (need < 0) cct_rt_fail("MOLDE rex fmt sizing failed");
    char *tmp = (char*)malloc((size_t)need + 1);
    if (!tmp) cct_rt_fail("MOLDE rex fmt allocation failed");
    int wrote = snprintf(tmp, (size_t)need + 1, fmt, v);
    if (wrote != need) cct_rt_fail("MOLDE rex fmt write failed");
    cct_rt_molde_append(m, tmp, (size_t)wrote);
    free(tmp);
}

static void cct_rt_molde_dux_fmt(cct_rt_molde_ctx_t *m, unsigned long long v, const char *spec) {
    char fmt[64];
    cct_rt_molde_fmt_build(fmt, sizeof(fmt), spec, "ll");
    int need = snprintf(NULL, 0, fmt, v);
    if (need < 0) cct_rt_fail("MOLDE dux fmt sizing failed");
    char *tmp = (char*)malloc((size_t)need + 1);
    if (!tmp) cct_rt_fail("MOLDE dux fmt allocation failed");
    int wrote = snprintf(tmp, (size_t)need + 1, fmt, v);
    if (wrote != need) cct_rt_fail("MOLDE dux fmt write failed");
    cct_rt_molde_append(m, tmp, (size_t)wrote);
    free(tmp);
}

static void cct_rt_molde_umbra_fmt(cct_rt_molde_ctx_t *m, double v, const char *spec) {
    char fmt[64];
    cct_rt_molde_fmt_build(fmt, sizeof(fmt), spec, NULL);
    int need = snprintf(NULL, 0, fmt, v);
    if (need < 0) cct_rt_fail("MOLDE umbra fmt sizing failed");
    char *tmp = (char*)malloc((size_t)need + 1);
    if (!tmp) cct_rt_fail("MOLDE umbra fmt allocation failed");
    int wrote = snprintf(tmp, (size_t)need + 1, fmt, v);
    if (wrote != need) cct_rt_fail("MOLDE umbra fmt write failed");
    cct_rt_molde_append(m, tmp, (size_t)wrote);
    free(tmp);
}

static int cct_rt_molde_parse_align_spec(const char *spec, char *dir, long long *width) {
    if (!spec || !dir || !width) return 0;
    if (spec[0] != '<' && spec[0] != '>') return 0;
    if (!spec[1]) return 0;
    long long acc = 0;
    for (size_t i = 1; spec[i]; i++) {
        if (spec[i] < '0' || spec[i] > '9') return 0;
        acc = (acc * 10LL) + (long long)(spec[i] - '0');
        if (acc < 0) cct_rt_fail("MOLDE alignment width overflow");
    }
    *dir = spec[0];
    *width = acc;
    return 1;
}

static void cct_rt_molde_append_spaces(cct_rt_molde_ctx_t *m, size_t count) {
    while (count > 0) {
        cct_rt_molde_append(m, " ", 1);
        count--;
    }
}

static void cct_rt_molde_str_fmt(cct_rt_molde_ctx_t *m, const char *s, const char *spec) {
    const char *src = s ? s : "";
    char dir = '\0';
    long long width = 0;
    if (cct_rt_molde_parse_align_spec(spec, &dir, &width)) {
        size_t slen = strlen(src);
        size_t pad = (width > (long long)slen) ? (size_t)(width - (long long)slen) : 0;
        if (dir == '>') cct_rt_molde_append_spaces(m, pad);
        cct_rt_molde_append(m, src, slen);
        if (dir == '<') cct_rt_molde_append_spaces(m, pad);
        return;
    }
    char fmt[64];
    cct_rt_molde_fmt_build(fmt, sizeof(fmt), spec, NULL);
    int need = snprintf(NULL, 0, fmt, src);
    if (need < 0) cct_rt_fail("MOLDE str fmt sizing failed");
    char *tmp = (char*)malloc((size_t)need + 1);
    if (!tmp) cct_rt_fail("MOLDE str fmt allocation failed");
    int wrote = snprintf(tmp, (size_t)need + 1, fmt, src);
    if (wrote != need) cct_rt_fail("MOLDE str fmt write failed");
    cct_rt_molde_append(m, tmp, (size_t)wrote);
    free(tmp);
}

static char *cct_rt_molde_end(cct_rt_molde_ctx_t *m) {
    if (!m) return NULL;
    char *out_s = m->buf;
    m->buf = NULL;
    free(m);
    return out_s;
}

static long long cct_rt_verbum_len(const char *s) {
    return (long long)strlen(s ? s : "");
}

static char *cct_rt_verbum_concat(const char *a, const char *b) {
    const char *sa = a ? a : "";
    const char *sb = b ? b : "";
    size_t la = strlen(sa);
    size_t lb = strlen(sb);
    char *out_s = (char*)malloc(la + lb + 1);
    if (!out_s) cct_rt_fail("verbum concat allocation failed");
    memcpy(out_s, sa, la);
    memcpy(out_s + la, sb, lb);
    out_s[la + lb] = '\0';
    return out_s;
}

static long long cct_rt_verbum_compare(const char *a, const char *b) {
    int cmp = strcmp(a ? a : "", b ? b : "");
    if (cmp < 0) return -1LL;
    if (cmp > 0) return 1LL;
    return 0LL;
}

static char *cct_rt_verbum_substring(const char *s, long long inicio, long long fim) {
    const char *src = s ? s : "";
    size_t slen = strlen(src);
    if (inicio < 0 || fim < 0 || inicio > fim || (size_t)fim > slen) {
        cct_rt_fail("verbum substring bounds invalid");
    }
    size_t start = (size_t)inicio;
    size_t end = (size_t)fim;
    size_t out_len = end - start;
    char *out_s = (char*)malloc(out_len + 1);
    if (!out_s) cct_rt_fail("verbum substring allocation failed");
    if (out_len > 0) memcpy(out_s, src + start, out_len);
    out_s[out_len] = '\0';
    return out_s;
}

static char *cct_rt_verbum_trim(const char *s) {
    const char *src = s ? s : "";
    size_t slen = strlen(src);
    size_t begin = 0;
    while (begin < slen && isspace((unsigned char)src[begin])) begin++;
    size_t end = slen;
    while (end > begin && isspace((unsigned char)src[end - 1])) end--;
    size_t out_len = end - begin;
    char *out_s = (char*)malloc(out_len + 1);
    if (!out_s) cct_rt_fail("verbum trim allocation failed");
    if (out_len > 0) memcpy(out_s, src + begin, out_len);
    out_s[out_len] = '\0';
    return out_s;
}

static long long cct_rt_verbum_find(const char *s, const char *sub) {
    const char *hay = s ? s : "";
    const char *needle = sub ? sub : "";
    if (*needle == '\0') return 0LL;
    const char *p = strstr(hay, needle);
    if (!p) return -1LL;
    return (long long)(p - hay);
}

static long long cct_rt_verbum_char_at(const char *s, long long i) {
    const char *src = s ? s : "";
    size_t n = strlen(src);
    if (i < 0 || (size_t)i >= n) cct_rt_fail("verbum char_at index out of bounds");
    return (long long)(unsigned char)src[(size_t)i];
}

static char *cct_rt_verbum_from_char(long long c) {
    if (c < 0 || c > 255) cct_rt_fail("verbum from_char expects byte range 0..255");
    char *out_s = (char*)malloc(2);
    if (!out_s) cct_rt_fail("verbum from_char allocation failed");
    out_s[0] = (char)(unsigned char)c;
    out_s[1] = '\0';
    return out_s;
}

static long long cct_rt_verbum_starts_with(const char *s, const char *prefix) {
    const char *src = s ? s : "";
    const char *pre = prefix ? prefix : "";
    size_t slen = strlen(src);
    size_t plen = strlen(pre);
    if (plen > slen) return 0LL;
    return (strncmp(src, pre, plen) == 0) ? 1LL : 0LL;
}

static long long cct_rt_verbum_ends_with(const char *s, const char *suffix) {
    const char *src = s ? s : "";
    const char *suf = suffix ? suffix : "";
    size_t slen = strlen(src);
    size_t suflen = strlen(suf);
    if (suflen > slen) return 0LL;
    return (memcmp(src + (slen - suflen), suf, suflen) == 0) ? 1LL : 0LL;
}

static char *cct_rt_verbum_strip_prefix(const char *s, const char *prefix) {
    const char *src = s ? s : "";
    const char *pre = prefix ? prefix : "";
    size_t slen = strlen(src);
    size_t plen = strlen(pre);
    if (!cct_rt_verbum_starts_with(src, pre)) return (char*)src;
    return cct_rt_verbum_substring(src, (long long)plen, (long long)slen);
}

static char *cct_rt_verbum_strip_suffix(const char *s, const char *suffix) {
    const char *src = s ? s : "";
    const char *suf = suffix ? suffix : "";
    size_t slen = strlen(src);
    size_t suflen = strlen(suf);
    if (!cct_rt_verbum_ends_with(src, suf)) return (char*)src;
    return cct_rt_verbum_substring(src, 0LL, (long long)(slen - suflen));
}

static char *cct_rt_verbum_replace(const char *s, const char *from, const char *to) {
    const char *src = s ? s : "";
    const char *needle = from ? from : "";
    const char *repl = to ? to : "";
    size_t from_len = strlen(needle);
    if (from_len == 0) return (char*)src;
    const char *found = strstr(src, needle);
    if (!found) return (char*)src;
    size_t pre = (size_t)(found - src);
    size_t to_len = strlen(repl);
    size_t src_len = strlen(src);
    size_t out_len = src_len - from_len + to_len;
    char *out_s = (char*)malloc(out_len + 1);
    if (!out_s) cct_rt_fail("verbum replace allocation failed");
    if (pre > 0) memcpy(out_s, src, pre);
    if (to_len > 0) memcpy(out_s + pre, repl, to_len);
    strcpy(out_s + pre + to_len, found + from_len);
    return out_s;
}

static char *cct_rt_verbum_replace_all(const char *s, const char *from, const char *to) {
    const char *src = s ? s : "";
    const char *needle = from ? from : "";
    const char *repl = to ? to : "";
    size_t from_len = strlen(needle);
    if (from_len == 0) return (char*)src;
    size_t to_len = strlen(repl);
    size_t src_len = strlen(src);
    size_t count = 0;
    const char *p = src;
    while ((p = strstr(p, needle)) != NULL) {
        count++;
        p += from_len;
    }
    if (count == 0) return (char*)src;
    size_t out_len = src_len;
    if (to_len >= from_len) {
        out_len += count * (to_len - from_len);
    } else {
        out_len -= count * (from_len - to_len);
    }
    char *out_s = (char*)malloc(out_len + 1);
    if (!out_s) cct_rt_fail("verbum replace_all allocation failed");
    const char *cur = src;
    char *w = out_s;
    while ((p = strstr(cur, needle)) != NULL) {
        size_t seg_len = (size_t)(p - cur);
        if (seg_len > 0) memcpy(w, cur, seg_len);
        w += seg_len;
        if (to_len > 0) memcpy(w, repl, to_len);
        w += to_len;
        cur = p + from_len;
    }
    strcpy(w, cur);
    return out_s;
}

static char *cct_rt_verbum_to_upper(const char *s) {
    const char *src = s ? s : "";
    size_t slen = strlen(src);
    char *out_s = (char*)malloc(slen + 1);
    if (!out_s) cct_rt_fail("verbum to_upper allocation failed");
    for (size_t i = 0; i < slen; i++) {
        unsigned char ch = (unsigned char)src[i];
        if (ch >= 'a' && ch <= 'z') ch = (unsigned char)(ch - ('a' - 'A'));
        out_s[i] = (char)ch;
    }
    out_s[slen] = '\0';
    return out_s;
}

static char *cct_rt_verbum_to_lower(const char *s) {
    const char *src = s ? s : "";
    size_t slen = strlen(src);
    char *out_s = (char*)malloc(slen + 1);
    if (!out_s) cct_rt_fail("verbum to_lower allocation failed");
    for (size_t i = 0; i < slen; i++) {
        unsigned char ch = (unsigned char)src[i];
        if (ch >= 'A' && ch <= 'Z') ch = (unsigned char)(ch + ('a' - 'A'));
        out_s[i] = (char)ch;
    }
    out_s[slen] = '\0';
    return out_s;
}

static char *cct_rt_verbum_trim_left(const char *s) {
    const char *src = s ? s : "";
    size_t slen = strlen(src);
    size_t begin = 0;
    while (begin < slen && isspace((unsigned char)src[begin])) begin++;
    size_t out_len = slen - begin;
    char *out_s = (char*)malloc(out_len + 1);
    if (!out_s) cct_rt_fail("verbum trim_left allocation failed");
    if (out_len > 0) memcpy(out_s, src + begin, out_len);
    out_s[out_len] = '\0';
    return out_s;
}

static char *cct_rt_verbum_trim_right(const char *s) {
    const char *src = s ? s : "";
    size_t end = strlen(src);
    while (end > 0 && isspace((unsigned char)src[end - 1])) end--;
    char *out_s = (char*)malloc(end + 1);
    if (!out_s) cct_rt_fail("verbum trim_right allocation failed");
    if (end > 0) memcpy(out_s, src, end);
    out_s[end] = '\0';
    return out_s;
}

static char *cct_rt_verbum_trim_char(const char *s, long long c) {
    const char *src = s ? s : "";
    if (c < 0 || c > 255) cct_rt_fail("verbum trim_char expects byte range 0..255");
    unsigned char ch = (unsigned char)c;
    size_t slen = strlen(src);
    size_t begin = 0;
    size_t end = slen;
    while (begin < slen && (unsigned char)src[begin] == ch) begin++;
    while (end > begin && (unsigned char)src[end - 1] == ch) end--;
    size_t out_len = end - begin;
    char *out_s = (char*)malloc(out_len + 1);
    if (!out_s) cct_rt_fail("verbum trim_char allocation failed");
    if (out_len > 0) memcpy(out_s, src + begin, out_len);
    out_s[out_len] = '\0';
    return out_s;
}

static char *cct_rt_verbum_repeat(const char *s, long long n) {
    const char *src = s ? s : "";
    if (n < 0) cct_rt_fail("verbum repeat count negativo");
    if (n == 0) return (char*)"";
    size_t slen = strlen(src);
    if (slen == 0) return (char*)"";
    size_t count = (size_t)n;
    if (slen > (SIZE_MAX - 1) / count) cct_rt_fail("verbum repeat allocation overflow");
    size_t out_len = slen * count;
    char *out_s = (char*)malloc(out_len + 1);
    if (!out_s) cct_rt_fail("verbum repeat allocation failed");
    char *w = out_s;
    for (size_t i = 0; i < count; i++) {
        memcpy(w, src, slen);
        w += slen;
    }
    out_s[out_len] = '\0';
    return out_s;
}

static char *cct_rt_verbum_pad_left(const char *s, long long width, long long fill) {
    const char *src = s ? s : "";
    if (fill < 0 || fill > 255) cct_rt_fail("verbum pad fill expects byte range 0..255");
    if (width < 0) return (char*)src;
    size_t slen = strlen(src);
    size_t w = (size_t)width;
    if (slen >= w) return (char*)src;
    size_t pad = w - slen;
    char *out_s = (char*)malloc(w + 1);
    if (!out_s) cct_rt_fail("verbum pad_left allocation failed");
    memset(out_s, (int)(unsigned char)fill, pad);
    memcpy(out_s + pad, src, slen);
    out_s[w] = '\0';
    return out_s;
}

static char *cct_rt_verbum_pad_right(const char *s, long long width, long long fill) {
    const char *src = s ? s : "";
    if (fill < 0 || fill > 255) cct_rt_fail("verbum pad fill expects byte range 0..255");
    if (width < 0) return (char*)src;
    size_t slen = strlen(src);
    size_t w = (size_t)width;
    if (slen >= w) return (char*)src;
    size_t pad = w - slen;
    char *out_s = (char*)malloc(w + 1);
    if (!out_s) cct_rt_fail("verbum pad_right allocation failed");
    memcpy(out_s, src, slen);
    memset(out_s + slen, (int)(unsigned char)fill, pad);
    out_s[w] = '\0';
    return out_s;
}

static char *cct_rt_verbum_center(const char *s, long long width, long long fill) {
    const char *src = s ? s : "";
    if (fill < 0 || fill > 255) cct_rt_fail("verbum pad fill expects byte range 0..255");
    if (width < 0) return (char*)src;
    size_t slen = strlen(src);
    size_t w = (size_t)width;
    if (slen >= w) return (char*)src;
    size_t total = w - slen;
    size_t left = total / 2;
    size_t right = total - left;
    char *out_s = (char*)malloc(w + 1);
    if (!out_s) cct_rt_fail("verbum center allocation failed");
    memset(out_s, (int)(unsigned char)fill, left);
    memcpy(out_s + left, src, slen);
    memset(out_s + left + slen, (int)(unsigned char)fill, right);
    out_s[w] = '\0';
    return out_s;
}

static long long cct_rt_verbum_last_find(const char *s, const char *sub) {
    const char *src = s ? s : "";
    const char *needle = sub ? sub : "";
    size_t slen = strlen(src);
    size_t nlen = strlen(needle);
    if (nlen == 0) return (long long)slen;
    const char *last = NULL;
    const char *p = src;
    while ((p = strstr(p, needle)) != NULL) {
        last = p;
        p += 1;
    }
    if (!last) return -1LL;
    return (long long)(last - src);
}

static long long cct_rt_verbum_find_from(const char *s, const char *sub, long long offset) {
    const char *src = s ? s : "";
    const char *needle = sub ? sub : "";
    size_t slen = strlen(src);
    if (offset < 0 || (size_t)offset > slen) cct_rt_fail("verbum find_from offset invalido");
    size_t nlen = strlen(needle);
    if (nlen == 0) return offset;
    size_t i = (size_t)offset;
    while (i + nlen <= slen) {
        if (memcmp(src + i, needle, nlen) == 0) return (long long)i;
        i++;
    }
    return -1LL;
}

static long long cct_rt_verbum_count_occurrences(const char *s, const char *sub) {
    const char *src = s ? s : "";
    const char *needle = sub ? sub : "";
    size_t nlen = strlen(needle);
    if (nlen == 0) return 0LL;
    long long count = 0;
    const char *p = src;
    while ((p = strstr(p, needle)) != NULL) {
        count++;
        p += nlen;
    }
    return count;
}

static char *cct_rt_verbum_reverse(const char *s) {
    const char *src = s ? s : "";
    size_t slen = strlen(src);
    char *out_s = (char*)malloc(slen + 1);
    if (!out_s) cct_rt_fail("verbum reverse allocation failed");
    for (size_t i = 0; i < slen; i++) {
        out_s[i] = src[slen - 1 - i];
    }
    out_s[slen] = '\0';
    return out_s;
}

static long long cct_rt_verbum_equals_ignore_case(const char *a, const char *b) {
    const char *sa = a ? a : "";
    const char *sb = b ? b : "";
    size_t la = strlen(sa);
    size_t lb = strlen(sb);
    if (la != lb) return 0LL;
    for (size_t i = 0; i < la; i++) {
        unsigned char ca = (unsigned char)sa[i];
        unsigned char cb = (unsigned char)sb[i];
        if (ca >= 'A' && ca <= 'Z') ca = (unsigned char)(ca + ('a' - 'A'));
        if (cb >= 'A' && cb <= 'Z') cb = (unsigned char)(cb + ('a' - 'A'));
        if (ca != cb) return 0LL;
    }
    return 1LL;
}

static char *cct_rt_verbum_slice(const char *s, long long inicio, long long comprimento) {
    const char *src = s ? s : "";
    long long slen = (long long)strlen(src);
    if (inicio < 0 || comprimento < 0 || inicio > slen || comprimento > (slen - inicio)) {
        cct_rt_fail("verbum slice bounds invalid");
    }
    return cct_rt_verbum_substring(src, inicio, inicio + comprimento);
}

static long long cct_rt_verbum_is_ascii(const char *s) {
    const char *src = s ? s : "";
    for (const unsigned char *p = (const unsigned char*)src; *p; ++p) {
        if (*p > 127U) return 0LL;
    }
    return 1LL;
}

static void *cct_rt_verbum_split(const char *s, const char *sep) {
    const char *src = s ? s : "";
    const char *delim = sep ? sep : "";
    size_t slen = strlen(src);
    size_t dlen = strlen(delim);
    cct_rt_fluxus_t *out_f = cct_rt_fluxus_create((long long)sizeof(char*));
    if (slen == 0) {
        char *empty = (char*)"";
        cct_rt_fluxus_push((void*)out_f, (const void*)&empty);
        return (void*)out_f;
    }
    if (dlen == 0) {
        for (size_t i = 0; i < slen; i++) {
            char *piece = cct_rt_verbum_substring(src, (long long)i, (long long)(i + 1));
            cct_rt_fluxus_push((void*)out_f, (const void*)&piece);
        }
        return (void*)out_f;
    }
    const char *cur = src;
    const char *p = strstr(cur, delim);
    while (p) {
        char *piece = cct_rt_verbum_substring(src, (long long)(cur - src), (long long)(p - src));
        cct_rt_fluxus_push((void*)out_f, (const void*)&piece);
        cur = p + dlen;
        p = strstr(cur, delim);
    }
    char *tail = cct_rt_verbum_substring(src, (long long)(cur - src), (long long)slen);
    cct_rt_fluxus_push((void*)out_f, (const void*)&tail);
    return (void*)out_f;
}

static void *cct_rt_verbum_split_char(const char *s, long long c) {
    if (c < 0 || c > 255) cct_rt_fail("verbum split_char expects byte range 0..255");
    char sep_buf[2];
    sep_buf[0] = (char)(unsigned char)c;
    sep_buf[1] = '\0';
    return cct_rt_verbum_split(s, sep_buf);
}

static char *cct_rt_verbum_join(void *parts_ptr, const char *sep) {
    if (!parts_ptr) cct_rt_fail("verbum join received null parts");
    cct_rt_fluxus_t *parts = (cct_rt_fluxus_t*)parts_ptr;
    if (parts->elem_size != (long long)sizeof(char*)) cct_rt_fail("verbum join requer fluxus de VERBUM");
    if (parts->len <= 0) return (char*)"";
    const char *delim = sep ? sep : "";
    size_t dlen = strlen(delim);
    char **items = (char**)parts->data;
    size_t total = 0;
    for (long long i = 0; i < parts->len; i++) {
        const char *piece = items[i] ? items[i] : "";
        size_t plen = strlen(piece);
        if (SIZE_MAX - total < plen) cct_rt_fail("verbum join allocation overflow");
        total += plen;
        if (i + 1 < parts->len) {
            if (SIZE_MAX - total < dlen) cct_rt_fail("verbum join allocation overflow");
            total += dlen;
        }
    }
    char *out_s = (char*)malloc(total + 1);
    if (!out_s) cct_rt_fail("verbum join allocation failed");
    char *w = out_s;
    for (long long i = 0; i < parts->len; i++) {
        const char *piece = items[i] ? items[i] : "";
        size_t plen = strlen(piece);
        if (plen > 0) {
            memcpy(w, piece, plen);
            w += plen;
        }
        if (i + 1 < parts->len && dlen > 0) {
            memcpy(w, delim, dlen);
            w += dlen;
        }
    }
    *w = '\0';
    return out_s;
}

static void *cct_rt_verbum_lines(const char *s) {
    cct_rt_fluxus_t *out_f = (cct_rt_fluxus_t*)cct_rt_verbum_split_char(s, 10LL);
    if (out_f->elem_size != (long long)sizeof(char*)) cct_rt_fail("verbum lines requer fluxus de VERBUM");
    char **items = (char**)out_f->data;
    for (long long i = 0; i < out_f->len; i++) {
        const char *piece = items[i] ? items[i] : "";
        size_t plen = strlen(piece);
        if (plen > 0 && (unsigned char)piece[plen - 1] == 13U) {
            items[i] = cct_rt_verbum_substring(piece, 0LL, (long long)(plen - 1));
        }
    }
    return (void*)out_f;
}

static void *cct_rt_verbum_words(const char *s) {
    const char *src = s ? s : "";
    size_t slen = strlen(src);
    cct_rt_fluxus_t *out_f = cct_rt_fluxus_create((long long)sizeof(char*));
    size_t i = 0;
    while (i < slen) {
        while (i < slen) {
            unsigned char ch = (unsigned char)src[i];
            if (!(ch == 32U || ch == 9U || ch == 10U || ch == 13U)) break;
            i++;
        }
        if (i >= slen) break;
        size_t start = i;
        while (i < slen) {
            unsigned char ch = (unsigned char)src[i];
            if (ch == 32U || ch == 9U || ch == 10U || ch == 13U) break;
            i++;
        }
        char *piece = cct_rt_verbum_substring(src, (long long)start, (long long)i);
        cct_rt_fluxus_push((void*)out_f, (const void*)&piece);
    }
    return (void*)out_f;
}

static long long cct_rt_char_is_digit(long long c) {
    return (c >= 48LL && c <= 57LL) ? 1LL : 0LL;
}

static long long cct_rt_char_is_alpha(long long c) {
    if (c >= 65LL && c <= 90LL) return 1LL;
    if (c >= 97LL && c <= 122LL) return 1LL;
    return 0LL;
}

static long long cct_rt_char_is_whitespace(long long c) {
    return (c == 32LL || c == 9LL || c == 10LL || c == 13LL) ? 1LL : 0LL;
}

static char *cct_rt_env_get(const char *name) {
    const char *k = name ? name : "";
    const char *v = getenv(k);
    return (char*)(v ? v : "");
}

static long long cct_rt_env_has(const char *name) {
    const char *k = name ? name : "";
    return getenv(k) ? 1LL : 0LL;
}

static char *cct_rt_env_cwd(void) {
    char buf[4096];
    if (!cct_rt_getcwd(buf, sizeof(buf))) cct_rt_fail("env cwd failed");
    size_t n = strlen(buf);
    char *out_s = (char*)malloc(n + 1);
    if (!out_s) cct_rt_fail("env cwd allocation failed");
    memcpy(out_s, buf, n + 1);
    return out_s;
}

typedef struct {
    const char *src;
    long long len;
    long long pos;
} cct_rt_scan_t;

static void *cct_rt_scan_init(const char *s) {
    cct_rt_scan_t *c = (cct_rt_scan_t*)malloc(sizeof(cct_rt_scan_t));
    if (!c) cct_rt_fail("scan init allocation failed");
    c->src = s ? s : "";
    c->len = (long long)strlen(c->src);
    c->pos = 0;
    return c;
}

static long long cct_rt_scan_pos(void *p) {
    cct_rt_scan_t *c = (cct_rt_scan_t*)p;
    if (!c) cct_rt_fail("scan pos null cursor");
    return c->pos;
}

static long long cct_rt_scan_eof(void *p) {
    cct_rt_scan_t *c = (cct_rt_scan_t*)p;
    if (!c) cct_rt_fail("scan eof null cursor");
    return (c->pos >= c->len) ? 1LL : 0LL;
}

static long long cct_rt_scan_peek(void *p) {
    cct_rt_scan_t *c = (cct_rt_scan_t*)p;
    if (!c) cct_rt_fail("scan peek null cursor");
    if (c->pos >= c->len) cct_rt_fail("scan peek at eof");
    return (long long)(unsigned char)c->src[c->pos];
}

static long long cct_rt_scan_next(void *p) {
    cct_rt_scan_t *c = (cct_rt_scan_t*)p;
    if (!c) cct_rt_fail("scan next null cursor");
    if (c->pos >= c->len) cct_rt_fail("scan next at eof");
    long long out_ch = (long long)(unsigned char)c->src[c->pos];
    c->pos += 1;
    return out_ch;
}

static void cct_rt_scan_free(void *p) {
    if (!p) return;
    free(p);
}

typedef struct {
    char *data;
    long long len;
    long long cap;
} cct_rt_builder_t;

static cct_rt_builder_t *cct_rt_builder_require_nonnull(void *p, const char *ctx) {
    cct_rt_builder_t *b = (cct_rt_builder_t*)p;
    if (!b) cct_rt_fail(ctx ? ctx : "builder null pointer");
    return b;
}

static void cct_rt_builder_reserve(cct_rt_builder_t *b, long long extra) {
    if (!b) cct_rt_fail("builder reserve null pointer");
    if (extra < 0) cct_rt_fail("builder reserve negative extra");
    if (b->cap <= 0) cct_rt_fail("builder reserve invalid capacity");
    long long need = b->len + extra + 1;
    if (need <= b->cap) return;
    long long new_cap = b->cap;
    while (new_cap < need) {
        if (new_cap > (9223372036854775807LL / 2)) {
            new_cap = need;
            break;
        }
        new_cap *= 2;
    }
    char *new_data = (char*)realloc(b->data, (size_t)new_cap);
    if (!new_data) cct_rt_fail("builder reserve allocation failed");
    b->data = new_data;
    b->cap = new_cap;
}

static void *cct_rt_builder_init(void) {
    cct_rt_builder_t *b = (cct_rt_builder_t*)malloc(sizeof(cct_rt_builder_t));
    if (!b) cct_rt_fail("builder init allocation failed");
    b->cap = 32;
    b->len = 0;
    b->data = (char*)malloc((size_t)b->cap);
    if (!b->data) cct_rt_fail("builder init buffer allocation failed");
    b->data[0] = '\0';
    return b;
}

static void cct_rt_builder_append(void *p, const char *s) {
    cct_rt_builder_t *b = cct_rt_builder_require_nonnull(p, "builder append null pointer");
    const char *src = s ? s : "";
    long long slen = (long long)strlen(src);
    cct_rt_builder_reserve(b, slen);
    memcpy(b->data + b->len, src, (size_t)slen + 1);
    b->len += slen;
}

static void cct_rt_builder_append_char(void *p, long long c) {
    cct_rt_builder_t *b = cct_rt_builder_require_nonnull(p, "builder append_char null pointer");
    if (c < 0 || c > 255) cct_rt_fail("builder append_char expects byte range 0..255");
    cct_rt_builder_reserve(b, 1);
    b->data[b->len] = (char)(unsigned char)c;
    b->len += 1;
    b->data[b->len] = '\0';
}

static long long cct_rt_builder_len(void *p) {
    cct_rt_builder_t *b = cct_rt_builder_require_nonnull(p, "builder len null pointer");
    return b->len;
}

static char *cct_rt_builder_to_verbum(void *p) {
    cct_rt_builder_t *b = cct_rt_builder_require_nonnull(p, "builder to_verbum null pointer");
    char *out_s = (char*)malloc((size_t)b->len + 1);
    if (!out_s) cct_rt_fail("builder to_verbum allocation failed");
    memcpy(out_s, b->data, (size_t)b->len + 1);
    return out_s;
}

static void cct_rt_builder_clear(void *p) {
    cct_rt_builder_t *b = cct_rt_builder_require_nonnull(p, "builder clear null pointer");
    b->len = 0;
    b->data[0] = '\0';
}

static void cct_rt_builder_free(void *p) {
    cct_rt_builder_t *b = (cct_rt_builder_t*)p;
    if (!b) return;
    free(b->data);
    free(b);
}

typedef struct {
    cct_rt_builder_t *buf;
    long long indent;
    int at_line_start;
} cct_rt_writer_t;

static cct_rt_writer_t *cct_rt_writer_require_nonnull(void *p, const char *ctx) {
    cct_rt_writer_t *w = (cct_rt_writer_t*)p;
    if (!w) cct_rt_fail(ctx ? ctx : "writer null pointer");
    return w;
}

static void cct_rt_writer_apply_indent(cct_rt_writer_t *w) {
    if (!w || !w->at_line_start) return;
    long long spaces = w->indent * 2;
    for (long long i = 0; i < spaces; i++) {
        cct_rt_builder_append_char((void*)w->buf, 32LL);
    }
    w->at_line_start = 0;
}

static void *cct_rt_writer_init(void) {
    cct_rt_writer_t *w = (cct_rt_writer_t*)malloc(sizeof(cct_rt_writer_t));
    if (!w) cct_rt_fail("writer init allocation failed");
    w->buf = (cct_rt_builder_t*)cct_rt_builder_init();
    w->indent = 0;
    w->at_line_start = 1;
    return w;
}

static void cct_rt_writer_indent(void *p) {
    cct_rt_writer_t *w = cct_rt_writer_require_nonnull(p, "writer indent null pointer");
    w->indent += 1;
}

static void cct_rt_writer_dedent(void *p) {
    cct_rt_writer_t *w = cct_rt_writer_require_nonnull(p, "writer dedent null pointer");
    if (w->indent <= 0) cct_rt_fail("writer dedent underflow");
    w->indent -= 1;
}

static void cct_rt_writer_write(void *p, const char *s) {
    cct_rt_writer_t *w = cct_rt_writer_require_nonnull(p, "writer write null pointer");
    const char *src = s ? s : "";
    size_t n = strlen(src);
    if (n == 0) return;
    cct_rt_writer_apply_indent(w);
    cct_rt_builder_append((void*)w->buf, src);
    w->at_line_start = (src[n - 1] == '\n') ? 1 : 0;
}

static void cct_rt_writer_writeln(void *p, const char *s) {
    cct_rt_writer_t *w = cct_rt_writer_require_nonnull(p, "writer writeln null pointer");
    const char *src = s ? s : "";
    cct_rt_writer_apply_indent(w);
    cct_rt_builder_append((void*)w->buf, src);
    cct_rt_builder_append_char((void*)w->buf, 10LL);
    w->at_line_start = 1;
}

static char *cct_rt_writer_to_verbum(void *p) {
    cct_rt_writer_t *w = cct_rt_writer_require_nonnull(p, "writer to_verbum null pointer");
    return cct_rt_builder_to_verbum((void*)w->buf);
}

static void cct_rt_writer_free(void *p) {
    cct_rt_writer_t *w = (cct_rt_writer_t*)p;
    if (!w) return;
    cct_rt_builder_free((void*)w->buf);
    free(w);
}

static char *cct_rt_fmt_stringify_int(long long x) {
    int n = snprintf(NULL, 0, "%lld", x);
    if (n < 0) cct_rt_fail("fmt stringify_int formatting failed");
    char *out_s = (char*)malloc((size_t)n + 1);
    if (!out_s) cct_rt_fail("fmt stringify_int allocation failed");
    snprintf(out_s, (size_t)n + 1, "%lld", x);
    return out_s;
}

static char *cct_rt_fmt_stringify_real(double x) {
    int n = snprintf(NULL, 0, "%.17g", x);
    if (n < 0) cct_rt_fail("fmt stringify_real formatting failed");
    char *out_s = (char*)malloc((size_t)n + 1);
    if (!out_s) cct_rt_fail("fmt stringify_real allocation failed");
    snprintf(out_s, (size_t)n + 1, "%.17g", x);
    return out_s;
}

static char *cct_rt_fmt_stringify_float(float x) {
    int n = snprintf(NULL, 0, "%.9g", (double)x);
    if (n < 0) cct_rt_fail("fmt stringify_float formatting failed");
    char *out_s = (char*)malloc((size_t)n + 1);
    if (!out_s) cct_rt_fail("fmt stringify_float allocation failed");
    snprintf(out_s, (size_t)n + 1, "%.9g", (double)x);
    return out_s;
}

static char *cct_rt_fmt_unsigned_base(unsigned long long v, unsigned base, const char *digits, const char *prefix) {
    if (base < 2U) cct_rt_fail("fmt stringify base invalida");
    const char *alpha = digits ? digits : "0123456789abcdef";
    const char *pre = prefix ? prefix : "";
    char buf[128];
    size_t i = sizeof(buf);
    buf[--i] = '\0';
    do {
        unsigned d = (unsigned)(v % (unsigned long long)base);
        buf[--i] = alpha[d];
        v /= (unsigned long long)base;
    } while (v > 0ULL);
    size_t pre_len = strlen(pre);
    size_t body_len = strlen(buf + i);
    char *out_s = (char*)malloc(pre_len + body_len + 1);
    if (!out_s) cct_rt_fail("fmt stringify base allocation failed");
    if (pre_len > 0) memcpy(out_s, pre, pre_len);
    memcpy(out_s + pre_len, buf + i, body_len + 1);
    return out_s;
}

static char *cct_rt_fmt_stringify_int_hex(long long x) {
    unsigned long long v = (x < 0) ? (((unsigned long long)x) & 0xffffffffULL) : (unsigned long long)x;
    return cct_rt_fmt_unsigned_base(v, 16U, "0123456789abcdef", "0x");
}

static char *cct_rt_fmt_stringify_int_hex_upper(long long x) {
    unsigned long long v = (x < 0) ? (((unsigned long long)x) & 0xffffffffULL) : (unsigned long long)x;
    return cct_rt_fmt_unsigned_base(v, 16U, "0123456789ABCDEF", "0x");
}

static char *cct_rt_fmt_stringify_int_oct(long long x) {
    unsigned long long v = (x < 0) ? (((unsigned long long)x) & 0xffffffffULL) : (unsigned long long)x;
    return cct_rt_fmt_unsigned_base(v, 8U, "01234567", "0o");
}

static char *cct_rt_fmt_stringify_int_bin(long long x) {
    unsigned long long v = (x < 0) ? (((unsigned long long)x) & 0xffffffffULL) : (unsigned long long)x;
    return cct_rt_fmt_unsigned_base(v, 2U, "01", "0b");
}

static char *cct_rt_fmt_stringify_uint(long long x) {
    if (x < 0) cct_rt_fail("fmt stringify_uint expects valor >= 0");
    unsigned long long v = (unsigned long long)x;
    int n = snprintf(NULL, 0, "%llu", v);
    if (n < 0) cct_rt_fail("fmt stringify_uint formatting failed");
    char *out_s = (char*)malloc((size_t)n + 1);
    if (!out_s) cct_rt_fail("fmt stringify_uint allocation failed");
    snprintf(out_s, (size_t)n + 1, "%llu", v);
    return out_s;
}

static char *cct_rt_fmt_stringify_int_padded(long long x, long long width, long long fill) {
    if (fill < 0 || fill > 255) cct_rt_fail("fmt stringify_int_padded fill fora do intervalo 0..255");
    char *base = cct_rt_fmt_stringify_int(x);
    if (width <= 0) return base;
    size_t len = strlen(base);
    size_t w = (size_t)width;
    if (len >= w) return base;
    size_t pad = w - len;
    char *out_s = (char*)malloc(w + 1);
    if (!out_s) cct_rt_fail("fmt stringify_int_padded allocation failed");
    memset(out_s, (int)(unsigned char)fill, pad);
    memcpy(out_s + pad, base, len + 1);
    return out_s;
}

static char *cct_rt_fmt_stringify_real_prec(double x, long long prec) {
    if (prec < 0) cct_rt_fail("fmt stringify_real_prec prec negativo");
    if (prec > 1000) cct_rt_fail("fmt stringify_real_prec prec invalido");
    int n = snprintf(NULL, 0, "%.*f", (int)prec, x);
    if (n < 0) cct_rt_fail("fmt stringify_real_prec formatting failed");
    char *out_s = (char*)malloc((size_t)n + 1);
    if (!out_s) cct_rt_fail("fmt stringify_real_prec allocation failed");
    snprintf(out_s, (size_t)n + 1, "%.*f", (int)prec, x);
    return out_s;
}

static char *cct_rt_fmt_stringify_real_sci(double x) {
    int n = snprintf(NULL, 0, "%e", x);
    if (n < 0) cct_rt_fail("fmt stringify_real_sci formatting failed");
    char *out_s = (char*)malloc((size_t)n + 1);
    if (!out_s) cct_rt_fail("fmt stringify_real_sci allocation failed");
    snprintf(out_s, (size_t)n + 1, "%e", x);
    return out_s;
}

static char *cct_rt_fmt_stringify_real_fixed(double x, long long prec) {
    if (prec < 0) cct_rt_fail("fmt stringify_real_fixed prec negativo");
    if (prec > 1000) cct_rt_fail("fmt stringify_real_fixed prec invalido");
    int n = snprintf(NULL, 0, "%.*f", (int)prec, x);
    if (n < 0) cct_rt_fail("fmt stringify_real_fixed formatting failed");
    char *out_s = (char*)malloc((size_t)n + 1);
    if (!out_s) cct_rt_fail("fmt stringify_real_fixed allocation failed");
    snprintf(out_s, (size_t)n + 1, "%.*f", (int)prec, x);
    return out_s;
}

static char *cct_rt_fmt_format_1(const char *tmpl, const char *a) {
    const char *src = tmpl ? tmpl : "";
    const char *arg = a ? a : "";
    const char *pos = strstr(src, "{}");
    if (!pos) return (char*)src;
    size_t pre = (size_t)(pos - src);
    size_t alen = strlen(arg);
    size_t rest = strlen(pos + 2);
    char *out_s = (char*)malloc(pre + alen + rest + 1);
    if (!out_s) cct_rt_fail("fmt format_1 allocation failed");
    if (pre > 0) memcpy(out_s, src, pre);
    if (alen > 0) memcpy(out_s + pre, arg, alen);
    memcpy(out_s + pre + alen, pos + 2, rest + 1);
    return out_s;
}

static char *cct_rt_fmt_format_2(const char *tmpl, const char *a, const char *b) {
    char *step1 = cct_rt_fmt_format_1(tmpl, a);
    return cct_rt_fmt_format_1(step1, b);
}

static char *cct_rt_fmt_format_3(const char *tmpl, const char *a, const char *b, const char *c) {
    char *step = cct_rt_fmt_format_2(tmpl, a, b);
    return cct_rt_fmt_format_1(step, c);
}

static char *cct_rt_fmt_format_4(const char *tmpl, const char *a, const char *b, const char *c, const char *d) {
    char *step = cct_rt_fmt_format_3(tmpl, a, b, c);
    return cct_rt_fmt_format_1(step, d);
}

static char *cct_rt_fmt_repeat_char(long long c, long long n) {
    if (c < 0 || c > 255) cct_rt_fail("fmt repeat_char expects byte range 0..255");
    if (n <= 0) return (char*)"";
    size_t count = (size_t)n;
    char *out_s = (char*)malloc(count + 1);
    if (!out_s) cct_rt_fail("fmt repeat_char allocation failed");
    memset(out_s, (int)(unsigned char)c, count);
    out_s[count] = '\0';
    return out_s;
}

static char *cct_rt_fmt_table_row(void *parts_ptr, const long long *widths, long long ncols) {
    if (!parts_ptr) cct_rt_fail("fmt table_row received null parts");
    if (!widths) cct_rt_fail("fmt table_row received null widths");
    if (ncols < 0) cct_rt_fail("fmt table_row ncols invalido");
    cct_rt_fluxus_t *parts = (cct_rt_fluxus_t*)parts_ptr;
    if (parts->elem_size != (long long)sizeof(char*)) cct_rt_fail("fmt table_row requer fluxus de VERBUM");
    char **items = (char**)parts->data;
    cct_rt_builder_t *b = (cct_rt_builder_t*)cct_rt_builder_init();
    for (long long i = 0; i < ncols; i++) {
        const char *piece = "";
        if (i < parts->len && items) piece = items[i] ? items[i] : "";
        long long w = widths[i];
        if (w < 0) w = 0;
        size_t plen = strlen(piece);
        size_t copy_n = plen;
        if ((long long)copy_n > w) copy_n = (size_t)w;
        if (copy_n > 0) {
            char *slice = cct_rt_verbum_substring(piece, 0LL, (long long)copy_n);
            cct_rt_builder_append((void*)b, slice);
        }
        for (long long pad = (long long)copy_n; pad < w; pad++) {
            cct_rt_builder_append_char((void*)b, 32LL);
        }
        if (i + 1 < ncols) cct_rt_builder_append((void*)b, " | ");
    }
    char *out_s = cct_rt_builder_to_verbum((void*)b);
    cct_rt_builder_free((void*)b);
    return out_s;
}

static long long cct_rt_fmt_parse_int_or_fail(const char *s) {
    const char *src = s ? s : "";
    while (*src && isspace((unsigned char)*src)) src++;
    if (!*src) cct_rt_fail("fmt parse_int invalid input");
    errno = 0;
    char *end = NULL;
    long long v = strtoll(src, &end, 10);
    if (errno != 0 || end == src) cct_rt_fail("fmt parse_int invalid input");
    while (*end && isspace((unsigned char)*end)) end++;
    if (*end) cct_rt_fail("fmt parse_int invalid input");
    return v;
}

static double cct_rt_fmt_parse_real_or_fail(const char *s) {
    const char *src = s ? s : "";
    while (*src && isspace((unsigned char)*src)) src++;
    if (!*src) cct_rt_fail("fmt parse_real invalid input");
    errno = 0;
    char *end = NULL;
    double v = strtod(src, &end);
    if (errno != 0 || end == src) cct_rt_fail("fmt parse_real invalid input");
    while (*end && isspace((unsigned char)*end)) end++;
    if (*end) cct_rt_fail("fmt parse_real invalid input");
    return v;
}

static int cct_rt_parse_has_edge_ws(const char *s) {
    const char *src = s ? s : "";
    size_t n = strlen(src);
    if (n == 0) return 1;
    if (isspace((unsigned char)src[0])) return 1;
    if (isspace((unsigned char)src[n - 1])) return 1;
    return 0;
}

static void *cct_rt_parse_try_int(const char *s) {
    const char *src = s ? s : "";
    if (cct_rt_parse_has_edge_ws(src)) return cct_rt_option_none(sizeof(long long));
    errno = 0;
    char *end = NULL;
    long long v = strtoll(src, &end, 10);
    if (errno != 0 || end == src || *end != '\0') return cct_rt_option_none(sizeof(long long));
    return cct_rt_option_some((const void*)&v, sizeof(long long));
}

static void *cct_rt_parse_try_real(const char *s) {
    const char *src = s ? s : "";
    if (cct_rt_parse_has_edge_ws(src)) return cct_rt_option_none(sizeof(double));
    errno = 0;
    char *end = NULL;
    double v = strtod(src, &end);
    if (errno != 0 || end == src || *end != '\0') return cct_rt_option_none(sizeof(double));
    return cct_rt_option_some((const void*)&v, sizeof(double));
}

static void *cct_rt_parse_try_bool(const char *s) {
    const char *src = s ? s : "";
    if (strcmp(src, "true") == 0) {
        long long v = 1LL;
        return cct_rt_option_some((const void*)&v, sizeof(long long));
    }
    if (strcmp(src, "false") == 0) {
        long long v = 0LL;
        return cct_rt_option_some((const void*)&v, sizeof(long long));
    }
    return cct_rt_option_none(sizeof(long long));
}

static long long cct_rt_parse_int_hex_raw(const char *s, int *ok) {
    const char *src = s ? s : "";
    if (ok) *ok = 0;
    if (cct_rt_parse_has_edge_ws(src)) return 0LL;
    size_t n = strlen(src);
    size_t pos = 0;
    if (src[pos] == '+' || src[pos] == '-') pos += 1;
    if (pos >= n) return 0LL;
    if (src[pos] == '0' && (pos + 1) < n && (src[pos + 1] == 'x' || src[pos + 1] == 'X')) pos += 2;
    if (pos >= n) return 0LL;
    errno = 0;
    char *end = NULL;
    long long v = strtoll(src, &end, 16);
    if (errno != 0 || end == src || *end != '\0') return 0LL;
    if (ok) *ok = 1;
    return v;
}

static void *cct_rt_parse_try_int_hex(const char *s) {
    int ok = 0;
    long long v = cct_rt_parse_int_hex_raw(s, &ok);
    if (!ok) return cct_rt_option_none(sizeof(long long));
    return cct_rt_option_some((const void*)&v, sizeof(long long));
}

static long long cct_rt_parse_int_hex(const char *s) {
    int ok = 0;
    long long v = cct_rt_parse_int_hex_raw(s, &ok);
    if (!ok) cct_rt_fail("parse parse_int_hex valor invalido");
    return v;
}

static void *cct_rt_parse_try_int_radix(const char *s, long long radix) {
    if (radix < 2LL || radix > 36LL) return cct_rt_option_none(sizeof(long long));
    const char *src = s ? s : "";
    if (cct_rt_parse_has_edge_ws(src)) return cct_rt_option_none(sizeof(long long));
    errno = 0;
    char *end = NULL;
    long long v = strtoll(src, &end, (int)radix);
    if (errno != 0 || end == src || *end != '\0') return cct_rt_option_none(sizeof(long long));
    return cct_rt_option_some((const void*)&v, sizeof(long long));
}

static long long cct_rt_parse_int_radix(const char *s, long long radix) {
    if (radix < 2LL || radix > 36LL) cct_rt_fail("parse parse_int_radix radix invalida");
    void *opt = cct_rt_parse_try_int_radix(s, radix);
    if (!cct_rt_option_is_some(opt)) cct_rt_fail("parse parse_int_radix valor invalido");
    long long out_v = *(long long*)cct_rt_option_unwrap_ptr(opt);
    cct_rt_option_free(opt);
    return out_v;
}

static long long cct_rt_parse_is_int(const char *s) {
    void *opt = cct_rt_parse_try_int(s);
    long long ok = cct_rt_option_is_some(opt);
    cct_rt_option_free(opt);
    return ok;
}

static long long cct_rt_parse_is_real(const char *s) {
    void *opt = cct_rt_parse_try_real(s);
    long long ok = cct_rt_option_is_some(opt);
    cct_rt_option_free(opt);
    return ok;
}

static void *cct_rt_parse_csv_line(const char *s, long long sep) {
    if (sep < 0LL || sep > 255LL) cct_rt_fail("parse parse_csv_line separador fora do intervalo 0..255");
    const char *src = s ? s : "";
    size_t n = strlen(src);
    size_t i = 0;
    unsigned char usep = (unsigned char)sep;
    cct_rt_fluxus_t *out_f = cct_rt_fluxus_create((long long)sizeof(char*));
    for (;;) {
        if (i == n) {
            char *empty = (char*)"";
            cct_rt_fluxus_push((void*)out_f, (const void*)&empty);
            break;
        }
        if ((unsigned char)src[i] == 34U) {
            size_t j = i + 1;
            while (j < n && (unsigned char)src[j] != 34U) j++;
            if (j >= n) cct_rt_fail("parse parse_csv_line aspas sem fechamento");
            char *field = cct_rt_verbum_substring(src, (long long)(i + 1), (long long)j);
            cct_rt_fluxus_push((void*)out_f, (const void*)&field);
            i = j + 1;
            if (i >= n) break;
            if ((unsigned char)src[i] != usep) cct_rt_fail("parse parse_csv_line formato invalido");
            i += 1;
            continue;
        }
        size_t j = i;
        while (j < n && (unsigned char)src[j] != usep) j++;
        char *field = cct_rt_verbum_substring(src, (long long)i, (long long)j);
        cct_rt_fluxus_push((void*)out_f, (const void*)&field);
        if (j >= n) break;
        i = j + 1;
    }
    return (void*)out_f;
}

static void cct_rt_io_print(const char *s) {
    fputs(s ? s : "", stdout);
}

static void cct_rt_io_println(const char *s) {
    fputs(s ? s : "", stdout);
    fputc('\n', stdout);
}

static void cct_rt_io_print_int(long long n) {
    printf("%lld", n);
}

static void cct_rt_io_print_real(double x) {
    printf("%g", x);
}

static void cct_rt_io_print_char(long long c) {
    if (c < -1 || c > 255) cct_rt_fail("io print_char expects byte range -1..255");
    if (c == -1) return;
    fputc((int)(unsigned char)c, stdout);
}

static void cct_rt_io_eprint(const char *s) {
    fputs(s ? s : "", stderr);
}

static void cct_rt_io_eprintln(const char *s) {
    fputs(s ? s : "", stderr);
    fputc('\n', stderr);
}

static void cct_rt_io_eprint_int(long long n) {
    fprintf(stderr, "%lld", n);
}

static void cct_rt_io_eprint_real(double x) {
    fprintf(stderr, "%g", x);
}

static void cct_rt_io_flush(void) {
    fflush(stdout);
}

static void cct_rt_io_flush_err(void) {
    fflush(stderr);
}

static long long cct_rt_io_read_char(void) {
    int ch = fgetc(stdin);
    if (ch == EOF) return -1LL;
    return (long long)(unsigned char)ch;
}

static long long cct_rt_io_is_tty(void) {
    return cct_rt_isatty(cct_rt_fileno(stdout)) ? 1LL : 0LL;
}

static char *cct_rt_io_read_line(void) {
    size_t cap = 128;
    size_t len = 0;
    char *buf = (char*)malloc(cap);
    if (!buf) cct_rt_fail("io read_line allocation failed");
    int ch = 0;
    while ((ch = fgetc(stdin)) != EOF) {
        if (ch == '\r') continue;
        if (ch == '\n') break;
        if (len + 1 >= cap) {
            size_t next_cap = cap * 2;
            char *next = (char*)realloc(buf, next_cap);
            if (!next) {
                free(buf);
                cct_rt_fail("io read_line reallocation failed");
            }
            buf = next;
            cap = next_cap;
        }
        buf[len++] = (char)ch;
    }
    buf[len] = '\0';
    return buf;
}

static FILE *cct_rt_fs_open_or_fail(const char *path, const char *mode, const char *ctx) {
    const char *p = path ? path : "";
    FILE *f = fopen(p, mode);
    if (!f) cct_rt_fail((ctx && *ctx) ? ctx : "fs open failed");
    return f;
}

static char *cct_rt_fs_make_atomic_tmp_path(const char *path) {
    static unsigned long counter = 0;
    const char *p = path ? path : "";
    size_t len = strlen(p);
    char *tmp = (char*)malloc(len + 64U);
    if (!tmp) cct_rt_fail("fs write_all tmp allocation failed");
    snprintf(tmp, len + 64U, "%s.tmp.%ld.%lu", p, (long)getpid(), ++counter);
    return tmp;
}

static char *cct_rt_fs_read_all(const char *path) {
    FILE *f = cct_rt_fs_open_or_fail(path, "rb", "fs read_all open failed");
    if (fseek(f, 0, SEEK_END) != 0) {
        fclose(f);
        cct_rt_fail("fs read_all seek-end failed");
    }
    long sz = ftell(f);
    if (sz < 0) {
        fclose(f);
        cct_rt_fail("fs read_all tell failed");
    }
    if (fseek(f, 0, SEEK_SET) != 0) {
        fclose(f);
        cct_rt_fail("fs read_all seek-set failed");
    }
    char *buf = (char*)malloc((size_t)sz + 1);
    if (!buf) {
        fclose(f);
        cct_rt_fail("fs read_all allocation failed");
    }
    size_t read_n = fread(buf, 1, (size_t)sz, f);
    if (read_n != (size_t)sz && ferror(f)) {
        free(buf);
        fclose(f);
        cct_rt_fail("fs read_all read failed");
    }
    buf[read_n] = '\0';
    fclose(f);
    return buf;
}

static void cct_rt_fs_write_all(const char *path, const char *content) {
    const char *dst = path ? path : "";
    char *tmp_path = cct_rt_fs_make_atomic_tmp_path(dst);
    FILE *f = cct_rt_fs_open_or_fail(tmp_path, "wb", "fs write_all open failed");
    const char *src = content ? content : "";
    size_t len = strlen(src);
    if (len > 0 && fwrite(src, 1, len, f) != len) {
        fclose(f);
        unlink(tmp_path);
        free(tmp_path);
        cct_rt_fail("fs write_all write failed");
    }
    if (fflush(f) != 0) {
        fclose(f);
        unlink(tmp_path);
        free(tmp_path);
        cct_rt_fail("fs write_all flush failed");
    }
#ifndef _WIN32
    if (fsync(fileno(f)) != 0) {
        fclose(f);
        unlink(tmp_path);
        free(tmp_path);
        cct_rt_fail("fs write_all sync failed");
    }
#endif
    if (fclose(f) != 0) {
        unlink(tmp_path);
        free(tmp_path);
        cct_rt_fail("fs write_all close failed");
    }
    if (rename(tmp_path, dst) != 0) {
        unlink(tmp_path);
        free(tmp_path);
        cct_rt_fail("fs write_all rename failed");
    }
    free(tmp_path);
}

static void cct_rt_fs_append_all(const char *path, const char *content) {
    FILE *f = cct_rt_fs_open_or_fail(path, "ab", "fs append_all open failed");
    const char *src = content ? content : "";
    size_t len = strlen(src);
    if (len > 0 && fwrite(src, 1, len, f) != len) {
        fclose(f);
        cct_rt_fail("fs append_all write failed");
    }
    fclose(f);
}

static long long cct_rt_fs_exists(const char *path) {
    const char *p = path ? path : "";
    FILE *f = fopen(p, "rb");
    if (!f) return 0LL;
    fclose(f);
    return 1LL;
}

static long long cct_rt_fs_size(const char *path) {
    FILE *f = cct_rt_fs_open_or_fail(path, "rb", "fs size open failed");
    if (fseek(f, 0, SEEK_END) != 0) {
        fclose(f);
        cct_rt_fail("fs size seek-end failed");
    }
    long sz = ftell(f);
    if (sz < 0) {
        fclose(f);
        cct_rt_fail("fs size tell failed");
    }
    fclose(f);
    return (long long)sz;
}

static void cct_rt_fs_fail1(const char *fmt, const char *a) {
    char msg[1024];
    const char *sa = a ? a : "";
    snprintf(msg, sizeof(msg), fmt ? fmt : "fs error", sa);
    cct_rt_fail(msg);
}

static void cct_rt_fs_fail2(const char *fmt, const char *a, const char *b) {
    char msg[1024];
    const char *sa = a ? a : "";
    const char *sb = b ? b : "";
    snprintf(msg, sizeof(msg), fmt ? fmt : "fs error", sa, sb);
    cct_rt_fail(msg);
}

static int cct_rt_fs_is_dir(const char *path) {
    struct stat st;
    if (stat(path ? path : "", &st) != 0) return 0;
    return S_ISDIR(st.st_mode) ? 1 : 0;
}

static long long cct_rt_fs_is_file(const char *path) {
    struct stat st;
    if (stat(path ? path : "", &st) != 0) return 0LL;
    return S_ISREG(st.st_mode) ? 1LL : 0LL;
}

static long long cct_rt_fs_is_symlink(const char *path) {
    struct stat st;
    if (lstat(path ? path : "", &st) != 0) return 0LL;
    return S_ISLNK(st.st_mode) ? 1LL : 0LL;
}

static long long cct_rt_fs_is_readable(const char *path) {
    const char *p = path ? path : "";
    return (access(p, R_OK) == 0) ? 1LL : 0LL;
}

static long long cct_rt_fs_is_writable(const char *path) {
    const char *p = path ? path : "";
    return (access(p, W_OK) == 0) ? 1LL : 0LL;
}

static long long cct_rt_fs_modified_time(const char *path) {
    struct stat st;
    const char *p = path ? path : "";
    if (stat(p, &st) != 0) cct_rt_fs_fail1("fs modified_time falhou: %s", p);
    return (long long)st.st_mtime;
}

static long long cct_rt_fs_same_file(const char *a, const char *b) {
    struct stat sa;
    struct stat sb;
    const char *pa = a ? a : "";
    const char *pb = b ? b : "";
    if (stat(pa, &sa) != 0) return 0LL;
    if (stat(pb, &sb) != 0) return 0LL;
    return (sa.st_dev == sb.st_dev && sa.st_ino == sb.st_ino) ? 1LL : 0LL;
}

static void cct_rt_fs_mkdir(const char *path) {
    const char *p = path ? path : "";
    if (cct_rt_mkdir(p) == 0) return;
    if (errno == EEXIST) cct_rt_fs_fail1("fs mkdir ja existe: %s", p);
    if (errno == ENOENT) cct_rt_fs_fail1("fs mkdir pai nao existe: %s", p);
    cct_rt_fs_fail1("fs mkdir falhou: %s", p);
}

static void cct_rt_fs_mkdir_all(const char *path) {
    const char *src = path ? path : "";
    size_t n = strlen(src);
    if (n == 0) return;
    char *tmp = (char*)malloc(n + 1);
    if (!tmp) cct_rt_fail("fs mkdir_all allocation failed");
    memcpy(tmp, src, n + 1);
    for (size_t i = 1; i < n; i++) {
        if (tmp[i] == '/' || tmp[i] == '\\') {
            char hold = tmp[i];
            tmp[i] = '\0';
            if (strlen(tmp) > 0) {
                if (cct_rt_mkdir(tmp) != 0 && errno != EEXIST) {
                    free(tmp);
                    cct_rt_fs_fail1("fs mkdir_all falhou: %s", src);
                }
            }
            tmp[i] = hold;
        }
    }
    if (cct_rt_mkdir(tmp) != 0) {
        if (errno != EEXIST || !cct_rt_fs_is_dir(tmp)) {
            free(tmp);
            cct_rt_fs_fail1("fs mkdir_all falhou: %s", src);
        }
    }
    free(tmp);
}

static void cct_rt_fs_delete_file(const char *path) {
    const char *p = path ? path : "";
    if (cct_rt_fs_is_dir(p)) cct_rt_fs_fail1("fs delete_file e um diretorio: %s", p);
    if (remove(p) == 0) return;
    if (errno == ENOENT) cct_rt_fs_fail1("fs delete_file nao encontrado: %s", p);
    cct_rt_fs_fail1("fs delete_file falhou: %s", p);
}

static void cct_rt_fs_delete_dir(const char *path) {
    const char *p = path ? path : "";
    if (rmdir(p) == 0) return;
    if (errno == ENOTEMPTY || errno == EEXIST) cct_rt_fs_fail1("fs delete_dir nao vazio: %s", p);
    cct_rt_fs_fail1("fs delete_dir falhou: %s", p);
}

static void cct_rt_fs_rename(const char *de, const char *para) {
    const char *src = de ? de : "";
    const char *dst = para ? para : "";
    if (rename(src, dst) == 0) return;
    if (errno == EXDEV) cct_rt_fail("fs rename cross-filesystem nao suportado");
    cct_rt_fs_fail2("fs rename falhou: %s -> %s", src, dst);
}

static void cct_rt_fs_copy(const char *de, const char *para) {
    const char *src = de ? de : "";
    const char *dst = para ? para : "";
    FILE *in = fopen(src, "rb");
    if (!in) cct_rt_fs_fail1("fs copy origem invalida: %s", src);
    FILE *out_f = fopen(dst, "wb");
    if (!out_f) {
        fclose(in);
        cct_rt_fs_fail1("fs copy destino invalido: %s", dst);
    }
    char buf[8192];
    for (;;) {
        size_t nread = fread(buf, 1, sizeof(buf), in);
        if (nread > 0 && fwrite(buf, 1, nread, out_f) != nread) {
            fclose(in);
            fclose(out_f);
            cct_rt_fs_fail1("fs copy write falhou: %s", dst);
        }
        if (nread < sizeof(buf)) {
            if (ferror(in)) {
                fclose(in);
                fclose(out_f);
                cct_rt_fs_fail1("fs copy read falhou: %s", src);
            }
            break;
        }
    }
    fclose(in);
    fclose(out_f);
}

static void cct_rt_fs_move(const char *de, const char *para) {
    const char *src = de ? de : "";
    const char *dst = para ? para : "";
    if (rename(src, dst) == 0) return;
    if (errno == EXDEV) {
        cct_rt_fs_copy(src, dst);
        cct_rt_fs_delete_file(src);
        return;
    }
    cct_rt_fs_fail2("fs move falhou: %s -> %s", src, dst);
}

static void cct_rt_fs_chmod(const char *path, long long mode) {
    const char *p = path ? path : "";
    if (mode < 0) cct_rt_fail("fs chmod mode invalido");
    if (chmod(p, (mode_t)mode) != 0) cct_rt_fs_fail1("fs chmod falhou: %s", p);
}

static void *cct_rt_fs_list_dir(const char *path) {
    const char *p = path ? path : "";
    DIR *dir = opendir(p);
    if (!dir) cct_rt_fs_fail1("fs list_dir falhou: %s", p);
    cct_rt_fluxus_t *out_f = cct_rt_fluxus_create((long long)sizeof(char*));
    struct dirent *ent = NULL;
    while ((ent = readdir(dir)) != NULL) {
        const char *name = ent->d_name;
        if (strcmp(name, ".") == 0 || strcmp(name, "..") == 0) continue;
        size_t n = strlen(name);
        char *copy = (char*)malloc(n + 1);
        if (!copy) {
            closedir(dir);
            cct_rt_fail("fs list_dir allocation failed");
        }
        memcpy(copy, name, n + 1);
        cct_rt_fluxus_push((void*)out_f, (const void*)&copy);
    }
    closedir(dir);
    return (void*)out_f;
}

static char *cct_rt_fs_tmp_template(const char *prefix) {
    const char *base = getenv("TMPDIR");
    const char *sp = prefix ? prefix : "cct_tmp_";
    if (!base || !*base) base = ".";
    size_t lb = strlen(base);
    size_t lp = strlen(sp);
    int need_sep = (lb > 0 && base[lb - 1] != '/' && base[lb - 1] != '\\');
    size_t total = lb + (need_sep ? 1U : 0U) + lp + 6U + 1U;
    char *tmpl = (char*)malloc(total);
    if (!tmpl) cct_rt_fail("fs temp allocation failed");
    snprintf(tmpl, total, "%s%s%sXXXXXX", base, need_sep ? "/" : "", sp);
    return tmpl;
}

static char *cct_rt_fs_create_temp_file(void) {
    char *tmpl = cct_rt_fs_tmp_template("cct_tmp_file_");
    int fd = mkstemp(tmpl);
    if (fd < 0) {
        free(tmpl);
        cct_rt_fail("fs create_temp_file falhou");
    }
    close(fd);
    return tmpl;
}

static char *cct_rt_fs_create_temp_dir(void) {
    char *tmpl = cct_rt_fs_tmp_template("cct_tmp_dir_");
    if (!mkdtemp(tmpl)) {
        free(tmpl);
        cct_rt_fail("fs create_temp_dir falhou");
    }
    return tmpl;
}

static void cct_rt_fs_truncate(const char *path, long long size) {
    const char *p = path ? path : "";
    if (size < 0) cct_rt_fail("fs truncate tamanho invalido");
    if (truncate(p, (off_t)size) != 0) cct_rt_fs_fail1("fs truncate falhou: %s", p);
}

static void cct_rt_fs_symlink(const char *alvo, const char *link) {
    const char *src = alvo ? alvo : "";
    const char *dst = link ? link : "";
    if (symlink(src, dst) != 0) cct_rt_fs_fail2("fs symlink falhou: %s -> %s", src, dst);
}

static int cct_rt_path_is_sep(char ch) {
    return ch == '/' || ch == '\\';
}

static char *cct_rt_path_dup_normalized(const char *src, size_t start, size_t end) {
    if (!src || end <= start) {
        char *empty = (char*)malloc(1);
        if (!empty) cct_rt_fail("path allocation failed");
        empty[0] = '\0';
        return empty;
    }
    size_t n = end - start;
    char *out_s = (char*)malloc(n + 1);
    if (!out_s) cct_rt_fail("path allocation failed");
    for (size_t i = 0; i < n; i++) {
        char ch = src[start + i];
        out_s[i] = (ch == '\\') ? '/' : ch;
    }
    out_s[n] = '\0';
    return out_s;
}

static char *cct_rt_path_join(const char *a, const char *b) {
    const char *sa = a ? a : "";
    const char *sb = b ? b : "";
    size_t la = strlen(sa);
    size_t lb = strlen(sb);
    if (la == 0) return cct_rt_path_dup_normalized(sb, 0, lb);
    if (lb == 0) return cct_rt_path_dup_normalized(sa, 0, la);

    size_t a_end = la;
    while (a_end > 0 && cct_rt_path_is_sep(sa[a_end - 1])) a_end--;
    int a_root_only = 0;
    if (a_end == 0) {
        for (size_t i = 0; i < la; i++) {
            if (!cct_rt_path_is_sep(sa[i])) { a_root_only = 0; break; }
            a_root_only = 1;
        }
    }

    size_t b_start = 0;
    while (b_start < lb && cct_rt_path_is_sep(sb[b_start])) b_start++;
    int b_all_sep = (b_start == lb);

    char *left = NULL;
    if (a_root_only) left = cct_rt_path_dup_normalized("/", 0, 1);
    else left = cct_rt_path_dup_normalized(sa, 0, a_end);

    if (b_all_sep) {
        size_t left_len = strlen(left);
        if (left_len == 0) {
            free(left);
            return cct_rt_path_dup_normalized("/", 0, 1);
        }
        if (left[left_len - 1] == '/') return left;
        char *out_s = (char*)malloc(left_len + 2);
        if (!out_s) {
            free(left);
            cct_rt_fail("path join allocation failed");
        }
        memcpy(out_s, left, left_len);
        out_s[left_len] = '/';
        out_s[left_len + 1] = '\0';
        free(left);
        return out_s;
    }

    char *right = cct_rt_path_dup_normalized(sb, b_start, lb);
    size_t left_len = strlen(left);
    size_t right_len = strlen(right);
    int left_is_root = (left_len == 1 && left[0] == '/');
    size_t out_len = left_len + right_len + (left_is_root ? 0 : 1);
    char *out_s = (char*)malloc(out_len + 1);
    if (!out_s) {
        free(left);
        free(right);
        cct_rt_fail("path join allocation failed");
    }
    size_t pos = 0;
    memcpy(out_s + pos, left, left_len);
    pos += left_len;
    if (!left_is_root) out_s[pos++] = '/';
    memcpy(out_s + pos, right, right_len);
    pos += right_len;
    out_s[pos] = '\0';
    free(left);
    free(right);
    return out_s;
}

static char *cct_rt_path_basename(const char *p) {
    const char *src = p ? p : "";
    size_t len = strlen(src);
    while (len > 0 && cct_rt_path_is_sep(src[len - 1])) len--;
    if (len == 0) return cct_rt_path_dup_normalized("", 0, 0);
    size_t start = len;
    while (start > 0 && !cct_rt_path_is_sep(src[start - 1])) start--;
    return cct_rt_path_dup_normalized(src, start, len);
}

static char *cct_rt_path_dirname(const char *p) {
    const char *src = p ? p : "";
    size_t slen = strlen(src);
    size_t len = slen;
    while (len > 0 && cct_rt_path_is_sep(src[len - 1])) len--;
    if (len == 0) {
        for (size_t i = 0; i < slen; i++) {
            if (!cct_rt_path_is_sep(src[i])) return cct_rt_path_dup_normalized("", 0, 0);
        }
        return (slen > 0) ? cct_rt_path_dup_normalized("/", 0, 1) : cct_rt_path_dup_normalized("", 0, 0);
    }
    size_t start = len;
    while (start > 0 && !cct_rt_path_is_sep(src[start - 1])) start--;
    if (start == 0) return cct_rt_path_dup_normalized("", 0, 0);
    size_t end = start;
    while (end > 0 && cct_rt_path_is_sep(src[end - 1])) end--;
    if (end == 0) return cct_rt_path_dup_normalized("/", 0, 1);
    return cct_rt_path_dup_normalized(src, 0, end);
}

static char *cct_rt_path_ext(const char *p) {
    char *base = cct_rt_path_basename(p);
    size_t len = strlen(base);
    size_t last_dot = (size_t)-1;
    for (size_t i = 0; i < len; i++) {
        if (base[i] == '.') last_dot = i;
    }
    if (last_dot == (size_t)-1 || last_dot == 0) {
        free(base);
        return cct_rt_path_dup_normalized("", 0, 0);
    }
    char *ext = cct_rt_path_dup_normalized(base, last_dot, len);
    free(base);
    return ext;
}

static long long cct_rt_path_is_absolute(const char *p) {
    const char *src = p ? p : "";
    return (src[0] == '/') ? 1LL : 0LL;
}

static void cct_rt_path_split_free(void *parts_ptr) {
    cct_rt_fluxus_t *parts = (cct_rt_fluxus_t*)parts_ptr;
    if (!parts) return;
    long long n = cct_rt_fluxus_len(parts);
    for (long long i = 0; i < n; i++) {
        char **pp = (char**)cct_rt_fluxus_get(parts, i);
        if (pp && *pp) free(*pp);
    }
    cct_rt_fluxus_destroy(parts);
}

static char *cct_rt_path_normalize(const char *p) {
    const char *src = p ? p : "";
    int is_abs = cct_rt_path_is_absolute(src) ? 1 : 0;
    size_t len = strlen(src);
    cct_rt_fluxus_t *stack = cct_rt_fluxus_create((long long)sizeof(char*));
    size_t i = 0;
    while (i < len) {
        while (i < len && cct_rt_path_is_sep(src[i])) i++;
        size_t start = i;
        while (i < len && !cct_rt_path_is_sep(src[i])) i++;
        size_t end = i;
        if (end <= start) continue;
        char *part = cct_rt_path_dup_normalized(src, start, end);
        if (strcmp(part, ".") == 0) {
            free(part);
            continue;
        }
        if (strcmp(part, "..") == 0) {
            long long n = cct_rt_fluxus_len(stack);
            if (n > 0) {
                char **top = (char**)cct_rt_fluxus_get(stack, n - 1);
                if (top && *top && strcmp(*top, "..") != 0) {
                    free(*top);
                    cct_rt_fluxus_remove(stack, n - 1);
                    free(part);
                    continue;
                }
            }
            if (is_abs) {
                free(part);
                continue;
            }
        }
        cct_rt_fluxus_push(stack, (const void*)&part);
    }
    long long n = cct_rt_fluxus_len(stack);
    if (n == 0) {
        cct_rt_fluxus_destroy(stack);
        if (is_abs) return cct_rt_path_dup_normalized("/", 0, 1);
        return cct_rt_path_dup_normalized(".", 0, 1);
    }
    char *joined = cct_rt_verbum_join(stack, "/");
    for (long long k = 0; k < n; k++) {
        char **pp = (char**)cct_rt_fluxus_get(stack, k);
        if (pp && *pp) free(*pp);
    }
    cct_rt_fluxus_destroy(stack);
    if (!is_abs) return joined;
    size_t jl = strlen(joined);
    char *out_s = (char*)malloc(jl + 2);
    if (!out_s) {
        free(joined);
        cct_rt_fail("path normalize allocation failed");
    }
    out_s[0] = '/';
    memcpy(out_s + 1, joined, jl + 1);
    free(joined);
    return out_s;
}

static char *cct_rt_path_without_ext(const char *p) {
    const char *src = p ? p : "";
    size_t len = strlen(src);
    size_t last_dot = (size_t)-1;
    size_t last_sep = (size_t)-1;
    for (size_t i = 0; i < len; i++) {
        if (src[i] == '.') last_dot = i;
        if (cct_rt_path_is_sep(src[i])) last_sep = i;
    }
    if (last_dot == (size_t)-1) return cct_rt_path_dup_normalized(src, 0, len);
    if (last_sep == (size_t)-1) {
        if (last_dot == 0) return cct_rt_path_dup_normalized(src, 0, len);
    } else if (last_dot <= last_sep + 1) {
        return cct_rt_path_dup_normalized(src, 0, len);
    }
    return cct_rt_path_dup_normalized(src, 0, last_dot);
}

static char *cct_rt_path_with_ext(const char *p, const char *ext) {
    char *core = cct_rt_path_without_ext(p);
    const char *sx = ext ? ext : "";
    if (*sx == '\0') return core;
    if (sx[0] == '.') {
        char *out_s = cct_rt_verbum_concat(core, sx);
        free(core);
        return out_s;
    }
    char *dot_ext = cct_rt_verbum_concat(".", sx);
    char *out_s = cct_rt_verbum_concat(core, dot_ext);
    free(dot_ext);
    free(core);
    return out_s;
}

static char *cct_rt_path_stem(const char *p) {
    char *base = cct_rt_path_basename(p);
    char *st = cct_rt_path_without_ext(base);
    free(base);
    return st;
}

static void *cct_rt_path_split(const char *p) {
    char *norm = cct_rt_path_normalize(p);
    int is_abs = cct_rt_path_is_absolute(norm) ? 1 : 0;
    cct_rt_fluxus_t *out_f = cct_rt_fluxus_create((long long)sizeof(char*));
    if (is_abs) {
        char *root = cct_rt_path_dup_normalized("/", 0, 1);
        cct_rt_fluxus_push(out_f, (const void*)&root);
    }
    size_t len = strlen(norm);
    size_t i = is_abs ? 1U : 0U;
    size_t start = i;
    while (i <= len) {
        if (i == len || norm[i] == '/') {
            if (i > start) {
                char *part = cct_rt_path_dup_normalized(norm, start, i);
                cct_rt_fluxus_push(out_f, (const void*)&part);
            }
            start = i + 1;
        }
        i++;
    }
    if (!is_abs && cct_rt_fluxus_len(out_f) == 0) {
        char *dot = cct_rt_path_dup_normalized(".", 0, 1);
        cct_rt_fluxus_push(out_f, (const void*)&dot);
    }
    free(norm);
    return (void*)out_f;
}

static char *cct_rt_path_resolve(const char *p) {
    const char *src = (p && *p) ? p : ".";
    char *resolved = NULL;
#ifdef _WIN32
    resolved = _fullpath(NULL, src, 0);
    if (resolved) {
        for (char *q = resolved; *q; ++q) if (*q == '\\') *q = '/';
        size_t resolved_len = strlen(resolved);
        char *copy = (char*)malloc(resolved_len + 1U);
        if (!copy) {
            cct_rt_mem_sys_free(resolved);
            cct_rt_fail("path resolve allocation failed");
        }
        memcpy(copy, resolved, resolved_len + 1U);
        cct_rt_mem_sys_free(resolved);
        return copy;
    }
#else
    resolved = realpath(src, NULL);
    if (resolved) {
        size_t resolved_len = strlen(resolved);
        char *copy = (char*)malloc(resolved_len + 1U);
        if (!copy) {
            cct_rt_mem_sys_free(resolved);
            cct_rt_fail("path resolve allocation failed");
        }
        memcpy(copy, resolved, resolved_len + 1U);
        cct_rt_mem_sys_free(resolved);
        return copy;
    }
#endif
    char *norm = cct_rt_path_normalize(src);
    if (cct_rt_path_is_absolute(norm)) return norm;
    char *cwd = cct_rt_getcwd(NULL, 0);
    if (!cwd) {
        free(norm);
        cct_rt_fail("path resolve cwd falhou");
    }
    char *joined = cct_rt_path_join(cwd, norm);
    cct_rt_mem_sys_free(cwd);
    free(norm);
    return joined;
}

static char *cct_rt_path_relative_to(const char *path, const char *base) {
    char *pn = cct_rt_path_normalize(path);
    char *bn = cct_rt_path_normalize(base);
    int pa = cct_rt_path_is_absolute(pn) ? 1 : 0;
    int ba = cct_rt_path_is_absolute(bn) ? 1 : 0;
    if (pa != ba) {
        free(pn);
        free(bn);
        cct_rt_fail("path relative_to requer ambos absolutos ou ambos relativos");
    }
    cct_rt_fluxus_t *pp = (cct_rt_fluxus_t*)cct_rt_path_split(pn);
    cct_rt_fluxus_t *bp = (cct_rt_fluxus_t*)cct_rt_path_split(bn);
    long long pi = pa ? 1LL : 0LL;
    long long bi = ba ? 1LL : 0LL;
    long long plen = cct_rt_fluxus_len(pp);
    long long blen = cct_rt_fluxus_len(bp);
    while (pi < plen && bi < blen) {
        char **pseg = (char**)cct_rt_fluxus_get(pp, pi);
        char **bseg = (char**)cct_rt_fluxus_get(bp, bi);
        const char *ps = (pseg && *pseg) ? *pseg : "";
        const char *bs = (bseg && *bseg) ? *bseg : "";
        if (strcmp(ps, bs) != 0) break;
        pi++;
        bi++;
    }
    cct_rt_fluxus_t *out_f = cct_rt_fluxus_create((long long)sizeof(char*));
    const char *up = "..";
    for (long long i = bi; i < blen; i++) cct_rt_fluxus_push(out_f, (const void*)&up);
    for (long long i = pi; i < plen; i++) {
        char **pseg = (char**)cct_rt_fluxus_get(pp, i);
        const char *ps = (pseg && *pseg) ? *pseg : "";
        if (*ps) cct_rt_fluxus_push(out_f, (const void*)pseg);
    }
    char *out_s = NULL;
    if (cct_rt_fluxus_len(out_f) == 0) out_s = cct_rt_path_dup_normalized(".", 0, 1);
    else out_s = cct_rt_verbum_join(out_f, "/");
    cct_rt_fluxus_destroy(out_f);
    cct_rt_path_split_free(pp);
    cct_rt_path_split_free(bp);
    free(pn);
    free(bn);
    return out_s;
}

static char *cct_rt_path_home_dir(void) {
    const char *home = getenv("HOME");
    if (home && *home) return cct_rt_path_dup_normalized(home, 0, strlen(home));
#ifdef _WIN32
    home = getenv("USERPROFILE");
    if (home && *home) return cct_rt_path_dup_normalized(home, 0, strlen(home));
#else
    struct passwd *pw = getpwuid(getuid());
    if (pw && pw->pw_dir && *pw->pw_dir) return cct_rt_path_dup_normalized(pw->pw_dir, 0, strlen(pw->pw_dir));
#endif
    cct_rt_fail("path home_dir nao disponivel");
    return cct_rt_path_dup_normalized("", 0, 0);
}

static char *cct_rt_path_temp_dir(void) {
    const char *tmp = getenv("TMPDIR");
    if (tmp && *tmp) return cct_rt_path_dup_normalized(tmp, 0, strlen(tmp));
#ifdef _WIN32
    tmp = getenv("TEMP");
    if (tmp && *tmp) return cct_rt_path_dup_normalized(tmp, 0, strlen(tmp));
    tmp = getenv("TMP");
    if (tmp && *tmp) return cct_rt_path_dup_normalized(tmp, 0, strlen(tmp));
#endif
    return cct_rt_path_dup_normalized("/tmp", 0, 4);
}

static void cct_rt_random_seed(long long s) {
    srand((unsigned int)(s & 0xFFFFFFFFu));
}

static long long cct_rt_random_int(long long lo, long long hi) {
    if (lo > hi) cct_rt_fail("random_int invalid range (lo > hi)");
    unsigned long long span = (unsigned long long)(hi - lo) + 1ULL;
    if (span == 0ULL) cct_rt_fail("random_int invalid range span overflow");
    unsigned long long r = (unsigned long long)rand();
    return lo + (long long)(r % span);
}

static double cct_rt_random_real(void) {
    return (double)rand() / ((double)RAND_MAX + 1.0);
}

static char *cct_rt_random_verbum(long long len) {
    static const char alphabet[] = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
    if (len < 0) cct_rt_fail("random_verbum len < 0");
    size_t n = (size_t)len;
    char *out_s = (char*)cct_rt_alloc_or_fail(n + 1U);
    size_t alpha_n = sizeof(alphabet) - 1U;
    for (size_t i = 0; i < n; i++) {
        out_s[i] = alphabet[(size_t)(rand() % (int)alpha_n)];
    }
    out_s[n] = '\0';
    return out_s;
}

static char *cct_rt_random_verbum_from(long long len, const char *alphabet) {
    if (len < 0) cct_rt_fail("random_verbum_from len < 0");
    if (!alphabet || !*alphabet) cct_rt_fail("random_verbum_from alphabet empty");
    size_t n = (size_t)len;
    size_t alpha_n = strlen(alphabet);
    char *out_s = (char*)cct_rt_alloc_or_fail(n + 1U);
    for (size_t i = 0; i < n; i++) {
        out_s[i] = alphabet[(size_t)(rand() % (int)alpha_n)];
    }
    out_s[n] = '\0';
    return out_s;
}

static void cct_rt_random_shuffle_int(long long *arr, long long n) {
    if (n < 0) cct_rt_fail("random_shuffle_int n < 0");
    if (n > 0 && !arr) cct_rt_fail("random_shuffle_int null arr");
    for (long long i = n - 1; i > 0; i--) {
        long long j = (long long)(rand() % (int)(i + 1));
        long long tmp = arr[i];
        arr[i] = arr[j];
        arr[j] = tmp;
    }
}

static void *cct_rt_random_bytes(long long len) {
    if (len < 0) cct_rt_fail("random_bytes len < 0");
    size_t n = (size_t)len;
    unsigned char *buf = (unsigned char*)cct_rt_alloc_or_fail(n == 0U ? 1U : n);
    for (size_t i = 0; i < n; i++) {
        buf[i] = (unsigned char)(rand() & 0xFF);
    }
    return (void*)buf;
}

static long long cct_rt_hash_fnv1a_bytes(const void *data, long long len) {
    if (len < 0) cct_rt_fail("hash_fnv1a_bytes len < 0");
    if (len > 0 && !data) cct_rt_fail("hash_fnv1a_bytes null data");
    const unsigned char *p = (const unsigned char*)data;
    uint64_t h = 14695981039346656037ULL;
    for (long long i = 0; i < len; i++) {
        h ^= (uint64_t)p[(size_t)i];
        h *= 1099511628211ULL;
    }
    return (long long)h;
}

static uint32_t cct_rt_hash_crc32_table[256];
static int cct_rt_hash_crc32_table_ready = 0;

static void cct_rt_hash_crc32_init(void) {
    if (cct_rt_hash_crc32_table_ready) return;
    for (uint32_t i = 0; i < 256U; i++) {
        uint32_t c = i;
        for (int j = 0; j < 8; j++) {
            if (c & 1U) c = (c >> 1) ^ 0xEDB88320U;
            else c >>= 1;
        }
        cct_rt_hash_crc32_table[i] = c;
    }
    cct_rt_hash_crc32_table_ready = 1;
}

static long long cct_rt_hash_crc32(const char *s) {
    cct_rt_hash_crc32_init();
    const unsigned char *p = (const unsigned char*)(s ? s : "");
    uint32_t crc = 0xFFFFFFFFU;
    while (*p) {
        uint32_t idx = (crc ^ (uint32_t)(*p++)) & 0xFFU;
        crc = (crc >> 8) ^ cct_rt_hash_crc32_table[idx];
    }
    return (long long)(crc ^ 0xFFFFFFFFU);
}

static uint32_t cct_rt_hash_rotl32(uint32_t x, int r) {
    return (x << r) | (x >> (32 - r));
}

static long long cct_rt_hash_murmur3(const char *s, long long seed) {
    const uint8_t *data = (const uint8_t*)(s ? s : "");
    size_t len = strlen((const char*)data);
    uint32_t h1 = (uint32_t)(seed & 0xFFFFFFFFULL);
    const uint32_t c1 = 0xcc9e2d51U;
    const uint32_t c2 = 0x1b873593U;
    size_t nblocks = len / 4U;
    for (size_t i = 0; i < nblocks; i++) {
        const uint8_t *blk = data + (i * 4U);
        uint32_t k1 = (uint32_t)blk[0] |
                      ((uint32_t)blk[1] << 8) |
                      ((uint32_t)blk[2] << 16) |
                      ((uint32_t)blk[3] << 24);
        k1 *= c1;
        k1 = cct_rt_hash_rotl32(k1, 15);
        k1 *= c2;
        h1 ^= k1;
        h1 = cct_rt_hash_rotl32(h1, 13);
        h1 = h1 * 5U + 0xe6546b64U;
    }
    const uint8_t *tail = data + (nblocks * 4U);
    uint32_t k1 = 0U;
    switch (len & 3U) {
        case 3: k1 ^= (uint32_t)tail[2] << 16; /* fallthrough */
        case 2: k1 ^= (uint32_t)tail[1] << 8;  /* fallthrough */
        case 1:
            k1 ^= (uint32_t)tail[0];
            k1 *= c1;
            k1 = cct_rt_hash_rotl32(k1, 15);
            k1 *= c2;
            h1 ^= k1;
            break;
        default:
            break;
    }
    h1 ^= (uint32_t)len;
    h1 ^= h1 >> 16;
    h1 *= 0x85ebca6bU;
    h1 ^= h1 >> 13;
    h1 *= 0xc2b2ae35U;
    h1 ^= h1 >> 16;
    return (long long)h1;
}

static long long cct_rt_process_decode_wait_status(int status) {
#ifdef _WIN32
    return (status == -1) ? -1LL : (long long)status;
#else
    if (status == -1) return -1LL;
    if (WIFEXITED(status)) return (long long)WEXITSTATUS(status);
    if (WIFSIGNALED(status)) return 128LL + (long long)WTERMSIG(status);
    return -1LL;
#endif
}

static char *cct_rt_process_read_stream(FILE *fp, const char *alloc_msg) {
    size_t cap = 256U;
    size_t len = 0U;
    char *buf = (char*)malloc(cap);
    if (!buf) cct_rt_fail((alloc_msg && *alloc_msg) ? alloc_msg : "process allocation failed");
    int ch = 0;
    while ((ch = fgetc(fp)) != EOF) {
        if (len + 1U >= cap) {
            size_t new_cap = cap * 2U;
            char *next = (char*)realloc(buf, new_cap);
            if (!next) {
                free(buf);
                cct_rt_fail((alloc_msg && *alloc_msg) ? alloc_msg : "process realloc failed");
            }
            buf = next;
            cap = new_cap;
        }
        buf[len++] = (char)ch;
    }
    buf[len] = '\0';
    return buf;
}

static long long cct_rt_process_run(const char *cmd) {
    const char *src = cmd ? cmd : "";
    int status = system(src);
    if (status == -1) cct_rt_fail("process run falhou");
    return cct_rt_process_decode_wait_status(status);
}

static char *cct_rt_process_run_capture(const char *cmd) {
    const char *src = cmd ? cmd : "";
    FILE *fp = popen(src, "r");
    if (!fp) cct_rt_fail("process run_capture popen falhou");
    char *buf = cct_rt_process_read_stream(fp, "process run_capture allocation failed");
    if (pclose(fp) == -1) cct_rt_fail("process run_capture pclose falhou");
    return buf;
}

static char *cct_rt_process_run_with_input(const char *cmd, const char *input) {
#ifdef _WIN32
    (void)cmd;
    (void)input;
    cct_rt_fail("process run_with_input unsupported on _WIN32");
    return "";
#else
    int stdin_pipe[2];
    int stdout_pipe[2];
    if (pipe(stdin_pipe) != 0 || pipe(stdout_pipe) != 0) cct_rt_fail("process run_with_input pipe falhou");
    pid_t pid = fork();
    if (pid < 0) cct_rt_fail("process run_with_input fork falhou");
    if (pid == 0) {
        close(stdin_pipe[1]);
        close(stdout_pipe[0]);
        if (dup2(stdin_pipe[0], STDIN_FILENO) < 0) _exit(127);
        if (dup2(stdout_pipe[1], STDOUT_FILENO) < 0) _exit(127);
        close(stdin_pipe[0]);
        close(stdout_pipe[1]);
        execl("/bin/sh", "sh", "-c", cmd ? cmd : "", (char*)NULL);
        _exit(127);
    }
    close(stdin_pipe[0]);
    close(stdout_pipe[1]);
    const char *src = input ? input : "";
    size_t left = strlen(src);
    const char *p = src;
    while (left > 0U) {
        ssize_t wrote = write(stdin_pipe[1], p, left);
        if (wrote < 0) {
            if (errno == EINTR) continue;
            if (errno == EPIPE) break;
            cct_rt_fail("process run_with_input write falhou");
        }
        p += (size_t)wrote;
        left -= (size_t)wrote;
    }
    close(stdin_pipe[1]);
    FILE *fp = fdopen(stdout_pipe[0], "r");
    if (!fp) {
        close(stdout_pipe[0]);
        cct_rt_fail("process run_with_input fdopen falhou");
    }
    char *captured = cct_rt_process_read_stream(fp, "process run_with_input capture allocation failed");
    fclose(fp);
    int status = 0;
    while (waitpid(pid, &status, 0) < 0) {
        if (errno == EINTR) {
            continue;
        }
        cct_rt_fail("process run_with_input waitpid falhou");
    }
    return captured;
#endif
}

static long long cct_rt_process_run_env(const char *cmd, void *env_pairs) {
#ifdef _WIN32
    (void)cmd;
    (void)env_pairs;
    cct_rt_fail("process run_env unsupported on _WIN32");
    return -1LL;
#else
    pid_t pid = fork();
    if (pid < 0) cct_rt_fail("process run_env fork falhou");
    if (pid == 0) {
        if (env_pairs) {
            long long n = cct_rt_fluxus_len(env_pairs);
            for (long long i = 0; i < n; i++) {
                char **slot = (char**)cct_rt_fluxus_get(env_pairs, i);
                const char *pair = (slot && *slot) ? *slot : "";
                const char *eq = strchr(pair, '=');
                if (!eq || eq == pair) continue;
                size_t key_len = (size_t)(eq - pair);
                char *key = (char*)malloc(key_len + 1U);
                if (!key) _exit(127);
                memcpy(key, pair, key_len);
                key[key_len] = '\0';
                setenv(key, eq + 1, 1);
                free(key);
            }
        }
        execl("/bin/sh", "sh", "-c", cmd ? cmd : "", (char*)NULL);
        _exit(127);
    }
    int status = 0;
    while (waitpid(pid, &status, 0) < 0) {
        if (errno == EINTR) continue;
        cct_rt_fail("process run_env waitpid falhou");
    }
    return cct_rt_process_decode_wait_status(status);
#endif
}

static long long cct_rt_process_run_timeout(const char *cmd, long long timeout_ms) {
    if (timeout_ms < 0) cct_rt_fail("process run_timeout timeout_ms invalido");
#ifdef _WIN32
    (void)cmd;
    cct_rt_fail("process run_timeout unsupported on _WIN32");
    return -1LL;
#else
    pid_t pid = fork();
    if (pid < 0) cct_rt_fail("process run_timeout fork falhou");
    if (pid == 0) {
        execl("/bin/sh", "sh", "-c", cmd ? cmd : "", (char*)NULL);
        _exit(127);
    }
    long long start = cct_rt_time_now_ms();
    int status = 0;
    for (;;) {
        pid_t waited = waitpid(pid, &status, WNOHANG);
        if (waited == pid) return cct_rt_process_decode_wait_status(status);
        if (waited < 0) {
            if (errno == EINTR) continue;
            cct_rt_fail("process run_timeout waitpid falhou");
        }
        long long now = cct_rt_time_now_ms();
        if (now - start >= timeout_ms) {
            kill(pid, SIGKILL);
            while (waitpid(pid, &status, 0) < 0) {
                if (errno == EINTR) continue;
                break;
            }
            return -1LL;
        }
        struct timespec req;
        req.tv_sec = 0;
        req.tv_nsec = 1000000L;
        nanosleep(&req, NULL);
    }
#endif
}

typedef struct {
    int fd;
    int kind;
    int domain;
    int closed;
    int owns_unix_path;
    char unix_path[108];
} cct_rt_socket_t;

static cct_rt_socket_t *cct_rt_socket_require(void *sock_ptr, const char *ctx) {
    cct_rt_socket_t *sock = (cct_rt_socket_t*)sock_ptr;
    if (!sock) cct_rt_fail((ctx && *ctx) ? ctx : "socket nulo");
    return sock;
}

static cct_rt_socket_t *cct_rt_socket_alloc(int fd, int kind, int domain) {
    if (fd < 0) cct_rt_fail("socket fd invalido");
    cct_rt_socket_t *sock = (cct_rt_socket_t*)cct_rt_alloc_or_fail(sizeof(cct_rt_socket_t));
    sock->fd = fd;
    sock->kind = kind;
    sock->domain = domain;
    sock->closed = 0;
    sock->owns_unix_path = 0;
    sock->unix_path[0] = '\0';
    return sock;
}

static void cct_rt_socket_check_open(cct_rt_socket_t *sock, const char *ctx) {
    if (!sock) cct_rt_fail((ctx && *ctx) ? ctx : "socket nulo");
    if (sock->closed || sock->fd < 0) cct_rt_fail((ctx && *ctx) ? ctx : "socket fechado");
}

static char *cct_rt_socket_empty_string(void) {
    char *buf = (char*)cct_rt_alloc_or_fail(1U);
    buf[0] = '\0';
    return buf;
}

static char cct_rt_socket_last_error[256] = "";

static char *cct_rt_socket_dup_cstr(const char *s) {
    const char *src = s ? s : "";
    size_t n = strlen(src);
    char *buf = (char*)cct_rt_alloc_or_fail(n + 1U);
    memcpy(buf, src, n + 1U);
    return buf;
}

static void cct_rt_socket_set_last_error(const char *msg) {
    const char *src = msg ? msg : "";
    size_t n = strlen(src);
    if (n >= sizeof(cct_rt_socket_last_error)) n = sizeof(cct_rt_socket_last_error) - 1U;
    memcpy(cct_rt_socket_last_error, src, n);
    cct_rt_socket_last_error[n] = '\0';
}

static void cct_rt_socket_clear_last_error(void) {
    cct_rt_socket_last_error[0] = '\0';
}

static char *cct_rt_sock_last_error(void) {
    return cct_rt_socket_dup_cstr(cct_rt_socket_last_error);
}

static char *cct_rt_socket_addr_string_from_sockaddr(const struct sockaddr *sa, socklen_t len) {
    if (!sa || len == 0) return cct_rt_socket_dup_cstr("");
    if (sa->sa_family == AF_INET && len >= (socklen_t)sizeof(struct sockaddr_in)) {
        const struct sockaddr_in *in = (const struct sockaddr_in*)sa;
        char host[INET_ADDRSTRLEN];
        if (!inet_ntop(AF_INET, &in->sin_addr, host, sizeof(host))) return cct_rt_socket_dup_cstr("inet:?");
        char out_buf[64];
        snprintf(out_buf, sizeof(out_buf), "%s:%u", host, (unsigned)ntohs(in->sin_port));
        return cct_rt_socket_dup_cstr(out_buf);
    }
    if (sa->sa_family == AF_UNIX && len >= (socklen_t)sizeof(struct sockaddr_un)) {
        const struct sockaddr_un *un = (const struct sockaddr_un*)sa;
        if (un->sun_path[0]) {
            char out_buf[160];
            snprintf(out_buf, sizeof(out_buf), "unix:%s", un->sun_path);
            return cct_rt_socket_dup_cstr(out_buf);
        }
        return cct_rt_socket_dup_cstr("unix");
    }
    return cct_rt_socket_dup_cstr("unknown");
}

static char *cct_rt_sock_peer_addr(void *sock_ptr) {
#ifdef _WIN32
    (void)sock_ptr;
    cct_rt_fail("sock_peer_addr unsupported on _WIN32");
    return "";
#else
    cct_rt_socket_t *sock = cct_rt_socket_require(sock_ptr, "sock_peer_addr recebeu socket nulo");
    cct_rt_socket_check_open(sock, "sock_peer_addr recebeu socket fechado");
    struct sockaddr_storage ss;
    socklen_t slen = (socklen_t)sizeof(ss);
    memset(&ss, 0, sizeof(ss));
    if (getpeername(sock->fd, (struct sockaddr*)&ss, &slen) != 0) {
        cct_rt_socket_set_last_error("sock_peer_addr falhou");
        return cct_rt_socket_empty_string();
    }
    cct_rt_socket_clear_last_error();
    return cct_rt_socket_addr_string_from_sockaddr((const struct sockaddr*)&ss, slen);
#endif
}

static char *cct_rt_sock_local_addr(void *sock_ptr) {
#ifdef _WIN32
    (void)sock_ptr;
    cct_rt_fail("sock_local_addr unsupported on _WIN32");
    return "";
#else
    cct_rt_socket_t *sock = cct_rt_socket_require(sock_ptr, "sock_local_addr recebeu socket nulo");
    cct_rt_socket_check_open(sock, "sock_local_addr recebeu socket fechado");
    struct sockaddr_storage ss;
    socklen_t slen = (socklen_t)sizeof(ss);
    memset(&ss, 0, sizeof(ss));
    if (getsockname(sock->fd, (struct sockaddr*)&ss, &slen) != 0) {
        cct_rt_socket_set_last_error("sock_local_addr falhou");
        return cct_rt_socket_empty_string();
    }
    cct_rt_socket_clear_last_error();
    return cct_rt_socket_addr_string_from_sockaddr((const struct sockaddr*)&ss, slen);
#endif
}

static void cct_rt_socket_enable_reuseaddr(int fd) {
    int yes = 1;
    (void)setsockopt(fd, SOL_SOCKET, SO_REUSEADDR, &yes, (socklen_t)sizeof(yes));
}

static void cct_rt_socket_validate_port(long long port) {
    if (port < 0 || port > 65535) cct_rt_fail("sock port invalido");
}

static int cct_rt_socket_is_local_host(const char *host) {
    if (!host || !*host) return 1;
    return strcmp(host, "127.0.0.1") == 0;
}

static void cct_rt_socket_make_unix_path(long long port, char out_path[108]) {
    cct_rt_socket_validate_port(port);
    int n = snprintf(out_path, 108, "tests/.tmp/cct_sock_%lld.sock", port);
    if (n <= 0 || n >= 108) cct_rt_fail("sock unix path invalido");
}

static void *cct_rt_socket_tcp(void) {
#ifdef _WIN32
    cct_rt_fail("socket_tcp unsupported on _WIN32");
    return NULL;
#else
    int fd = socket(AF_INET, SOCK_STREAM, 0);
    if (fd < 0) {
        cct_rt_socket_set_last_error("socket tcp create falhou");
        cct_rt_fractum_throw_str("socket tcp create falhou");
        return (void*)&cct_rt_null_sentinel;
    }
    cct_rt_socket_clear_last_error();
    return (void*)cct_rt_socket_alloc(fd, SOCK_STREAM, AF_INET);
#endif
}

static void *cct_rt_socket_udp(void) {
#ifdef _WIN32
    cct_rt_fail("socket_udp unsupported on _WIN32");
    return NULL;
#else
    int fd = socket(AF_INET, SOCK_DGRAM, 0);
    if (fd < 0) {
        cct_rt_socket_set_last_error("socket udp create falhou");
        cct_rt_fractum_throw_str("socket udp create falhou");
        return (void*)&cct_rt_null_sentinel;
    }
    cct_rt_socket_clear_last_error();
    return (void*)cct_rt_socket_alloc(fd, SOCK_DGRAM, AF_INET);
#endif
}

static void cct_rt_sock_connect(void *sock_ptr, const char *host, long long port) {
#ifdef _WIN32
    (void)sock_ptr;
    (void)host;
    (void)port;
    cct_rt_fail("sock_connect unsupported on _WIN32");
#else
    cct_rt_socket_t *sock = cct_rt_socket_require(sock_ptr, "sock_connect recebeu socket nulo");
    cct_rt_socket_check_open(sock, "sock_connect recebeu socket fechado");
    cct_rt_socket_validate_port(port);
    struct sockaddr_in addr;
    memset(&addr, 0, sizeof(addr));
    addr.sin_family = AF_INET;
    addr.sin_port = htons((uint16_t)port);
    const char *node = (host && *host) ? host : "127.0.0.1";
    if (inet_pton(AF_INET, node, &addr.sin_addr) != 1) cct_rt_fail("sock_connect host invalido");
    if (connect(sock->fd, (const struct sockaddr*)&addr, (socklen_t)sizeof(addr)) == 0) {
        sock->domain = AF_INET;
        cct_rt_socket_clear_last_error();
        return;
    }
    if (!cct_rt_socket_is_local_host(host)) {
        cct_rt_socket_set_last_error("sock_connect falhou");
        cct_rt_fail("sock_connect falhou");
    }
    char unix_path[108];
    cct_rt_socket_make_unix_path(port, unix_path);
    int ufd = socket(AF_UNIX, sock->kind, 0);
    if (ufd < 0) {
        cct_rt_socket_set_last_error("sock_connect falhou");
        cct_rt_fail("sock_connect falhou");
    }
    struct sockaddr_un uaddr;
    memset(&uaddr, 0, sizeof(uaddr));
    uaddr.sun_family = AF_UNIX;
    strncpy(uaddr.sun_path, unix_path, sizeof(uaddr.sun_path) - 1);
    uaddr.sun_path[sizeof(uaddr.sun_path) - 1] = '\0';
    if (connect(ufd, (const struct sockaddr*)&uaddr, (socklen_t)sizeof(uaddr)) != 0) {
        close(ufd);
        cct_rt_socket_set_last_error("sock_connect falhou");
        cct_rt_fail("sock_connect falhou");
    }
    (void)close(sock->fd);
    sock->fd = ufd;
    sock->domain = AF_UNIX;
    sock->owns_unix_path = 0;
    sock->unix_path[0] = '\0';
    cct_rt_socket_clear_last_error();
#endif
}

static void cct_rt_sock_bind(void *sock_ptr, const char *host, long long port) {
#ifdef _WIN32
    (void)sock_ptr;
    (void)host;
    (void)port;
    cct_rt_fail("sock_bind unsupported on _WIN32");
#else
    cct_rt_socket_t *sock = cct_rt_socket_require(sock_ptr, "sock_bind recebeu socket nulo");
    cct_rt_socket_check_open(sock, "sock_bind recebeu socket fechado");
    cct_rt_socket_validate_port(port);
    struct sockaddr_in addr;
    memset(&addr, 0, sizeof(addr));
    addr.sin_family = AF_INET;
    addr.sin_port = htons((uint16_t)port);
    if (!host || !*host) addr.sin_addr.s_addr = htonl(INADDR_ANY);
    else if (inet_pton(AF_INET, host, &addr.sin_addr) != 1) cct_rt_fail("sock_bind host invalido");
    cct_rt_socket_enable_reuseaddr(sock->fd);
    if (bind(sock->fd, (const struct sockaddr*)&addr, (socklen_t)sizeof(addr)) == 0) {
        sock->domain = AF_INET;
        sock->owns_unix_path = 0;
        sock->unix_path[0] = '\0';
        cct_rt_socket_clear_last_error();
        return;
    }
    if (!cct_rt_socket_is_local_host(host)) {
        cct_rt_socket_set_last_error("sock_bind falhou");
        cct_rt_fractum_throw_str("sock_bind falhou");
        return;
    }
    char unix_path[108];
    cct_rt_socket_make_unix_path(port, unix_path);
    int ufd = socket(AF_UNIX, sock->kind, 0);
    if (ufd < 0) {
        cct_rt_socket_set_last_error("sock_bind falhou");
        cct_rt_fractum_throw_str("sock_bind falhou");
        return;
    }
    struct sockaddr_un uaddr;
    memset(&uaddr, 0, sizeof(uaddr));
    uaddr.sun_family = AF_UNIX;
    strncpy(uaddr.sun_path, unix_path, sizeof(uaddr.sun_path) - 1);
    uaddr.sun_path[sizeof(uaddr.sun_path) - 1] = '\0';
    unlink(unix_path);
    if (bind(ufd, (const struct sockaddr*)&uaddr, (socklen_t)sizeof(uaddr)) != 0) {
        close(ufd);
        cct_rt_socket_set_last_error("sock_bind falhou");
        cct_rt_fractum_throw_str("sock_bind falhou");
        return;
    }
    (void)close(sock->fd);
    sock->fd = ufd;
    sock->domain = AF_UNIX;
    sock->owns_unix_path = 1;
    strncpy(sock->unix_path, unix_path, sizeof(sock->unix_path) - 1);
    sock->unix_path[sizeof(sock->unix_path) - 1] = '\0';
    cct_rt_socket_clear_last_error();
#endif
}

static void cct_rt_sock_listen(void *sock_ptr, long long backlog) {
#ifdef _WIN32
    (void)sock_ptr;
    (void)backlog;
    cct_rt_fail("sock_listen unsupported on _WIN32");
#else
    cct_rt_socket_t *sock = cct_rt_socket_require(sock_ptr, "sock_listen recebeu socket nulo");
    cct_rt_socket_check_open(sock, "sock_listen recebeu socket fechado");
    if (backlog < 0) cct_rt_fail("sock_listen backlog invalido");
    if (listen(sock->fd, (int)backlog) != 0) {
        cct_rt_socket_set_last_error("sock_listen falhou");
        cct_rt_fail("sock_listen falhou");
    }
    cct_rt_socket_clear_last_error();
#endif
}

static void *cct_rt_sock_accept(void *sock_ptr) {
#ifdef _WIN32
    (void)sock_ptr;
    cct_rt_fail("sock_accept unsupported on _WIN32");
    return NULL;
#else
    cct_rt_socket_t *sock = cct_rt_socket_require(sock_ptr, "sock_accept recebeu socket nulo");
    cct_rt_socket_check_open(sock, "sock_accept recebeu socket fechado");
    for (;;) {
        fd_set rfds;
        struct timeval tv;
        int ready = 0;
        FD_ZERO(&rfds);
        FD_SET(sock->fd, &rfds);
        tv.tv_sec = 0;
        tv.tv_usec = 200000;
        ready = select(sock->fd + 1, &rfds, NULL, NULL, &tv);
        if (ready == 0) {
            if (cct_rt_signal_check_shutdown()) cct_rt_fail("server stopping");
            continue;
        }
        if (ready < 0) {
            if (errno == EINTR) {
                if (cct_rt_signal_check_shutdown()) cct_rt_fail("server stopping");
                continue;
            }
            cct_rt_socket_set_last_error("sock_accept falhou");
            cct_rt_fail("sock_accept falhou");
        }
        int fd = accept(sock->fd, NULL, NULL);
        if (fd >= 0) {
            cct_rt_socket_clear_last_error();
            return (void*)cct_rt_socket_alloc(fd, sock->kind, sock->domain);
        }
        if (errno == EINTR) {
            if (cct_rt_signal_check_shutdown()) cct_rt_fail("server stopping");
            continue;
        }
        cct_rt_socket_set_last_error("sock_accept falhou");
        cct_rt_fail("sock_accept falhou");
    }
#endif
}

static long long cct_rt_sock_send(void *sock_ptr, const char *data) {
#ifdef _WIN32
    (void)sock_ptr;
    (void)data;
    cct_rt_fail("sock_send unsupported on _WIN32");
    return 0LL;
#else
    cct_rt_socket_t *sock = cct_rt_socket_require(sock_ptr, "sock_send recebeu socket nulo");
    cct_rt_socket_check_open(sock, "sock_send recebeu socket fechado");
    const char *src = data ? data : "";
    size_t total = strlen(src);
    size_t sent = 0U;
    while (sent < total) {
        ssize_t rc = send(sock->fd, src + sent, total - sent, 0);
        if (rc > 0) {
            sent += (size_t)rc;
            continue;
        }
        if (rc < 0 && errno == EINTR) continue;
        cct_rt_socket_set_last_error("sock_send falhou");
        cct_rt_fail("sock_send falhou");
    }
    cct_rt_socket_clear_last_error();
    return (long long)sent;
#endif
}

static char *cct_rt_sock_recv(void *sock_ptr, long long max_bytes) {
#ifdef _WIN32
    (void)sock_ptr;
    (void)max_bytes;
    cct_rt_fail("sock_recv unsupported on _WIN32");
    return "";
#else
    cct_rt_socket_t *sock = cct_rt_socket_require(sock_ptr, "sock_recv recebeu socket nulo");
    cct_rt_socket_check_open(sock, "sock_recv recebeu socket fechado");
    if (max_bytes < 0) cct_rt_fail("sock_recv max_bytes invalido");
    if (max_bytes == 0) return cct_rt_socket_empty_string();
    char *buf = (char*)cct_rt_alloc_or_fail((size_t)max_bytes + 1U);
    for (;;) {
        ssize_t rc = recv(sock->fd, buf, (size_t)max_bytes, 0);
        if (rc > 0) {
            buf[rc] = '\0';
            cct_rt_socket_clear_last_error();
            return buf;
        }
        if (rc == 0) {
            buf[0] = '\0';
            cct_rt_socket_clear_last_error();
            return buf;
        }
        if (errno == EINTR) continue;
        if (errno == EAGAIN || errno == EWOULDBLOCK) {
            cct_rt_free_ptr(buf);
            cct_rt_socket_clear_last_error();
            return cct_rt_socket_empty_string();
        }
        cct_rt_free_ptr(buf);
        cct_rt_socket_set_last_error("sock_recv falhou");
        cct_rt_fail("sock_recv falhou");
    }
#endif
}

static void cct_rt_sock_close(void *sock_ptr) {
#ifdef _WIN32
    (void)sock_ptr;
    cct_rt_fail("sock_close unsupported on _WIN32");
#else
    cct_rt_socket_t *sock = (cct_rt_socket_t*)sock_ptr;
    if (!sock) return;
    if (!sock->closed && sock->fd >= 0) {
        while (close(sock->fd) != 0) {
            if (errno == EINTR) continue;
            break;
        }
    }
    if (sock->owns_unix_path && sock->unix_path[0]) {
        (void)unlink(sock->unix_path);
    }
    sock->fd = -1;
    sock->closed = 1;
    sock->owns_unix_path = 0;
    sock->unix_path[0] = '\0';
#endif
}

static void cct_rt_sock_set_timeout_ms(void *sock_ptr, long long timeout_ms) {
#ifdef _WIN32
    (void)sock_ptr;
    (void)timeout_ms;
    cct_rt_fail("sock_set_timeout_ms unsupported on _WIN32");
#else
    cct_rt_socket_t *sock = cct_rt_socket_require(sock_ptr, "sock_set_timeout_ms recebeu socket nulo");
    cct_rt_socket_check_open(sock, "sock_set_timeout_ms recebeu socket fechado");
    if (timeout_ms < 0) cct_rt_fail("sock_set_timeout_ms invalido");
    struct timeval tv;
    tv.tv_sec = (time_t)(timeout_ms / 1000LL);
    tv.tv_usec = (suseconds_t)((timeout_ms % 1000LL) * 1000LL);
    if (setsockopt(sock->fd, SOL_SOCKET, SO_RCVTIMEO, &tv, (socklen_t)sizeof(tv)) != 0) {
        cct_rt_socket_set_last_error("sock_set_timeout_ms recv falhou");
        cct_rt_fail("sock_set_timeout_ms recv falhou");
    }
    if (setsockopt(sock->fd, SOL_SOCKET, SO_SNDTIMEO, &tv, (socklen_t)sizeof(tv)) != 0) {
        cct_rt_socket_set_last_error("sock_set_timeout_ms send falhou");
        cct_rt_fail("sock_set_timeout_ms send falhou");
    }
    cct_rt_socket_clear_last_error();
#endif
}

typedef struct {
    regex_t compiled;
    long long flags;
} cct_rt_regex_t;

static char cct_rt_regex_last_error_buf[256] = {0};

static void cct_rt_regex_set_error(const char *msg) {
    snprintf(cct_rt_regex_last_error_buf, sizeof(cct_rt_regex_last_error_buf), "%s", (msg && *msg) ? msg : "regex failure");
}

static char *cct_rt_regex_dup_span(const char *src, size_t len) {
    char *out_s = (char*)cct_rt_alloc_or_fail(len + 1u);
    if (len > 0u) memcpy(out_s, src, len);
    out_s[len] = '\0';
    return out_s;
}

static void cct_rt_regex_push_verbum(void *flux_ptr, const char *src, size_t len) {
    char *copy = cct_rt_regex_dup_span(src, len);
    cct_rt_fluxus_push(flux_ptr, (const void*)&copy);
}

static void *cct_rt_regex_compile(const char *pattern, long long flags) {
    cct_rt_regex_t *rx = (cct_rt_regex_t*)cct_rt_alloc_or_fail(sizeof(cct_rt_regex_t));
    int cflags = REG_EXTENDED;
    if (flags & 1LL) cflags |= REG_ICASE;
    if (flags & 2LL) cflags |= REG_NEWLINE;
    int rc = regcomp(&rx->compiled, pattern ? pattern : "", cflags);
    if (rc != 0) {
        regerror(rc, &rx->compiled, cct_rt_regex_last_error_buf, sizeof(cct_rt_regex_last_error_buf));
        cct_rt_free_ptr(rx);
        return NULL;
    }
    rx->flags = flags;
    cct_rt_regex_last_error_buf[0] = '\0';
    return rx;
}

static char *cct_rt_regex_last_error(void) {
    return cct_rt_regex_last_error_buf;
}

static long long cct_rt_regex_match(void *handle, const char *text) {
    if (!handle) return 0LL;
    cct_rt_regex_t *rx = (cct_rt_regex_t*)handle;
    regmatch_t match;
    int rc = regexec(&rx->compiled, text ? text : "", 1, &match, 0);
    if (rc != 0) return 0LL;
    size_t len = strlen(text ? text : "");
    return (match.rm_so == 0 && match.rm_eo == (regoff_t)len) ? 1LL : 0LL;
}

static char *cct_rt_regex_search(void *handle, const char *text) {
    if (!handle) return cct_rt_regex_dup_span("", 0u);
    cct_rt_regex_t *rx = (cct_rt_regex_t*)handle;
    regmatch_t match;
    const char *src = text ? text : "";
    int rc = regexec(&rx->compiled, src, 1, &match, 0);
    if (rc != 0 || match.rm_so < 0 || match.rm_eo < match.rm_so) return cct_rt_regex_dup_span("", 0u);
    return cct_rt_regex_dup_span(src + match.rm_so, (size_t)(match.rm_eo - match.rm_so));
}

static void *cct_rt_regex_find_all(void *handle, const char *text) {
    void *flux = cct_rt_fluxus_create((long long)sizeof(char*));
    if (!handle) return flux;
    cct_rt_regex_t *rx = (cct_rt_regex_t*)handle;
    const char *cursor = text ? text : "";
    size_t offset = 0u;
    size_t total_len = strlen(cursor);
    while (offset <= total_len) {
        regmatch_t match;
        int rc = regexec(&rx->compiled, cursor + offset, 1, &match, 0);
        if (rc != 0 || match.rm_so < 0 || match.rm_eo < match.rm_so) break;
        size_t start = offset + (size_t)match.rm_so;
        size_t end = offset + (size_t)match.rm_eo;
        cct_rt_regex_push_verbum(flux, cursor + start, end - start);
        if (match.rm_eo == match.rm_so) {
            if (offset == total_len) break;
            offset += 1u;
        } else {
            offset = end;
        }
    }
    return flux;
}

static char *cct_rt_regex_replace(void *handle, const char *text, const char *replacement, long long all) {
    if (!handle) return cct_rt_regex_dup_span(text ? text : "", strlen(text ? text : ""));
    cct_rt_regex_t *rx = (cct_rt_regex_t*)handle;
    const char *src = text ? text : "";
    const char *rep = replacement ? replacement : "";
    size_t src_len = strlen(src);
    size_t rep_len = strlen(rep);
    size_t cap = src_len + rep_len + 16u;
    char *out_s = (char*)cct_rt_alloc_or_fail(cap);
    size_t out_len = 0u;
    size_t offset = 0u;
    while (offset <= src_len) {
        regmatch_t match;
        int rc = regexec(&rx->compiled, src + offset, 1, &match, 0);
        if (rc != 0 || match.rm_so < 0 || match.rm_eo < match.rm_so) break;
        size_t start = offset + (size_t)match.rm_so;
        size_t end = offset + (size_t)match.rm_eo;
        size_t prefix = start - offset;
        while (out_len + prefix + rep_len + 1u > cap) { cap *= 2u; out_s = (char*)realloc(out_s, cap); if (!out_s) cct_rt_fail("regex replace realloc failed"); }
        if (prefix > 0u) memcpy(out_s + out_len, src + offset, prefix);
        out_len += prefix;
        if (rep_len > 0u) memcpy(out_s + out_len, rep, rep_len);
        out_len += rep_len;
        if (!all) { offset = end; break; }
        if (match.rm_eo == match.rm_so) {
            if (offset == src_len) break;
            while (out_len + 2u > cap) { cap *= 2u; out_s = (char*)realloc(out_s, cap); if (!out_s) cct_rt_fail("regex replace realloc failed"); }
            out_s[out_len++] = src[offset];
            offset += 1u;
        } else {
            offset = end;
        }
    }
    if (offset < src_len) {
        size_t tail = src_len - offset;
        while (out_len + tail + 1u > cap) { cap *= 2u; out_s = (char*)realloc(out_s, cap); if (!out_s) cct_rt_fail("regex replace realloc failed"); }
        memcpy(out_s + out_len, src + offset, tail);
        out_len += tail;
    }
    out_s[out_len] = '\0';
    return out_s;
}

static void *cct_rt_regex_split(void *handle, const char *text) {
    void *flux = cct_rt_fluxus_create((long long)sizeof(char*));
    const char *src = text ? text : "";
    if (!handle) {
        cct_rt_regex_push_verbum(flux, src, strlen(src));
        return flux;
    }
    cct_rt_regex_t *rx = (cct_rt_regex_t*)handle;
    size_t src_len = strlen(src);
    size_t offset = 0u;
    while (offset <= src_len) {
        regmatch_t match;
        int rc = regexec(&rx->compiled, src + offset, 1, &match, 0);
        if (rc != 0 || match.rm_so < 0 || match.rm_eo < match.rm_so) break;
        size_t start = offset + (size_t)match.rm_so;
        size_t end = offset + (size_t)match.rm_eo;
        cct_rt_regex_push_verbum(flux, src + offset, start - offset);
        if (match.rm_eo == match.rm_so) {
            if (offset == src_len) break;
            offset += 1u;
        } else {
            offset = end;
        }
    }
    cct_rt_regex_push_verbum(flux, src + offset, src_len - offset);
    return flux;
}

static void cct_rt_regex_free(void *handle) {
    if (!handle) return;
    cct_rt_regex_t *rx = (cct_rt_regex_t*)handle;
    regfree(&rx->compiled);
    cct_rt_free_ptr(rx);
}

