typedef struct AstNode AstNode;
typedef struct AstProgram AstProgram;
typedef struct SourceLocation SourceLocation;
typedef struct LexerState LexerState;
typedef struct Token Token;
typedef struct ParserState ParserState;
typedef struct SemanticContext SemanticContext;
typedef struct SemanticScope SemanticScope;
typedef struct SemanticSymbol SemanticSymbol;
typedef struct SemanticType SemanticType;

struct AstNode {
    long long kind;
    long long line;
    long long column;
    const char * name;
    long long owns_name;
    const char * value_text;
    long long owns_value_text;
    const char * type_name;
    long long owns_type_name;
    const char * aux_name;
    long long owns_aux_name;
    const char * fmt_spec;
    long long owns_fmt_spec;
    long long operator_kind;
    long long bool_value;
    long long array_size;
    long long is_pointer;
    long long is_array;
    long long has_left;
    long long has_right;
    long long has_condition;
    long long has_body;
    long long has_else_branch;
    long long has_callee;
    long long has_type_expr;
    long long has_return_type;
    long long has_try_block;
    long long has_cape_type;
    long long has_cape_block;
    long long has_semper_block;
    AstNode * left;
    AstNode * right;
    AstNode * condition;
    AstNode * body;
    AstNode * else_branch;
    AstNode * callee;
    AstNode * type_expr;
    AstNode * return_type;
    AstNode * try_block;
    AstNode * cape_type;
    AstNode * cape_block;
    AstNode * semper_block;
    void * children;
    void * cases;
    void * bindings;
    void * type_params;
    void * generic_args;
    void * params;
    void * fields;
    void * items;
    void * arguments;
    void * declarations;
    void * signatures;
    void * statements;
};

struct AstProgram {
    const char * name;
    long long owns_name;
    void * declarations;
};

struct SourceLocation {
    const char * filename;
    long long line;
    long long column;
};

struct LexerState {
    const char * source;
    long long source_len;
    long long current;
    long long start;
    long long line;
    long long column;
    const char * filename;
    long long had_error;
};

struct Token {
    long long kind;
    const char * lexeme;
    long long line;
    long long column;
};

struct ParserState {
    LexerState * lexer;
    Token current;
    Token previous;
    long long had_error;
    long long panic_mode;
    const char * filename;
};

struct SemanticContext {
    const char * filename;
    long long owns_filename;
    long long had_error;
    long long error_count;
    const char * last_error_message;
    long long owns_last_error_message;
    long long last_error_line;
    long long last_error_column;
    void * scopes;
    void * symbols;
    void * types;
    void * instance_cache_type_ids;
    void * instance_cache_hashes;
    long long global_scope_id;
    long long current_scope_id;
    long long current_rituale_id;
    long long loop_depth;
    long long type_error;
    long long type_nihil;
    long long type_verum;
    long long type_verbum;
    long long type_fractum;
    long long type_rex;
    long long type_dux;
    long long type_comes;
    long long type_miles;
    long long type_umbra;
    long long type_flamma;
};

struct SemanticScope {
    long long id;
    long long kind;
    long long parent_id;
    void * symbol_ids;
    long long depth;
};

struct SemanticSymbol {
    long long id;
    const char * name;
    long long owns_name;
    long long kind;
    long long type_id;
    long long payload_type_id;
    long long owner_symbol_id;
    long long constraint_symbol_id;
    long long generic_scope_id;
    AstNode * decl_node;
    long long has_decl_node;
    void * param_type_ids;
    void * type_param_ids;
    long long line;
    long long column;
};

struct SemanticType {
    long long id;
    long long kind;
    const char * name;
    long long owns_name;
    long long is_builtin;
    long long element_type_id;
    long long array_size;
    long long named_symbol_id;
    long long owner_symbol_id;
    long long constraint_symbol_id;
    long long generic_origin_symbol_id;
    void * type_arg_ids;
    const char * canonical_key;
    long long owns_canonical_key;
    long long canonical_hash;
};

